  "Cargo.toml": "[package]
name = "character_deserialize"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"",
  "main.rs": "use serde::Deserialize;

// Helper struct to capture the JSON structure exactly
#[derive(Deserialize)]
struct CharacterInput {
    name: String,
    ac: u8,
    hp: u16,
}

// Final struct with duplicate HP values split into current/max
#[derive(Debug)]
struct Character {
    name: String,
    ac: u8,
    current: u16,
    max: u16,
    temp: u16,
}

impl From<CharacterInput> for Character {
    fn from(input: CharacterInput) -> Self {
        Character {
            name: input.name,
            ac: input.ac,
            current: input.hp,
            max: input.hp,
            temp: 0,
        }
    }
}

fn main() {
    let json = r#"{
        "name": "Henry",
        "ac": 16,
        "hp": 54
    }"#;

    // First deserialize into the input struct
    let input: CharacterInput = serde_json::from_str(json)
        .expect("Failed to deserialize input");

    // Convert to our desired Character struct
    let character: Character = input.into();

    println!("Name: {}", character.name);
    println!("AC: {}", character.ac);
    println!("Current HP: {}", character.current);
    println!("Max HP: {}", character.max);
    println!("Temp HP: {}", character.temp);
}"
}

