  "main.rs": "use serde::de::{self, Deserialize, Deserializer, MapAccess, Visitor};
use std::fmt;
use std::marker::PhantomData;

// Define enum B
#[derive(Debug, Clone)]
enum B {
    Option1,
    Option2,
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        let s = String::deserialize(deserializer)?;
        match s.as_str() {
            "Option1" => Ok(B::Option1),
            "Option2" => Ok(B::Option2),
            _ => Err(de::Error::custom("unknown variant")),
        }
    }
}

// Define struct A
#[derive(Debug)]
struct A {
    x: usize,
    b: Vec<B>,
}

// Custom visitor for A
struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("struct A")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut x: Option<usize> = None;
        let mut b: Option<Vec<B>> = None;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "x" => {
                    if x.is_some() {
                        return Err(de::Error::duplicate_field("x"));
                    }
                    x = Some(map.next_value()?);
                }
                "b" => {
                    if b.is_some() {
                        return Err(de::Error::duplicate_field("b"));
                    }
                    b = Some(map.next_value()?);
                }
                _ => {
                    // Skip unknown fields or error out
                    map.next_value::<de::IgnoredAny>()?;
                }
            }
        }

        Ok(A {
            x: x.ok_or_else(|| de::Error::missing_field("x"))?,
            b: b.unwrap_or_default(),
        })
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        const FIELDS: &[&str] = &["x", "b"];
        deserializer.deserialize_struct("A", FIELDS, AVisitor)
    }
}

fn main() {
    // Example JSON input
    let json = r#"{
        "x": 42,
        "b": ["Option1", "Option2", "Option1"]
    }"#;

    // Deserialize using custom deserializer
    let a: A = serde_json::from_str(json).expect("Failed to deserialize A");
    println!("Deserialized A: {:?}", a);
    println!("a.x = {}", a.x);
    println!("a.b.len() = {}", a.b.len());

    // Also test default/empty b field
    let json2 = r#"{"x": 100}"#;
    let a2: A = serde_json::from_str(json2).expect("Failed to deserialize A2");
    println!("\nDeserialized A2: {:?}", a2);
    println!("a2.x = {}", a2.x);
    println!("a2.b.len() = {}", a2.b.len());

    // Test error case
    let json3 = r#"{"x": 5, "b": ["Invalid"]}"#;
    match serde_json::from_str::<A>(json3) {
        Ok(_) => println!("This shouldn't print"),
        Err(e) => println!("\nExpected error: {}", e),
    }
}"
}

