  "main.rs": "use polars::prelude::*;

fn main() -> PolarsResult<()> {
    // Create sample input data
    let df = df! {
        "col1" => &[Some("val1"), Some("val2")]  
    }?;

    println!("Input DataFrame:");
    println!("{}\n", df);

    // Transform each row into a list of structs
    let result_df = df
        .lazy()
        .with_column(
            col("col1").apply(
                |s| {
                    let s_str = s.str()?;

                    // Build a StructChunked representing one struct per input row
                    let mut struct_builder = StructChunkedBuilder::new(
                        PlSmallStr::from_static("inner_struct"),
