use std::convert::Infallible;

type ObservableType = LocalBoxedObservableClone<'static, bool, Infallible>;

fn nand_gate(name: &str, a: ObservableType, b: ObservableType) -> ObservableType {
    a.combine_latest(b, |a, b| (a, b))
        .distinct()
        .tap(move |(_, _)| println!("nand {}: computing", name))
        .map(|(a, b)| !(a & b))
        .tap(|v| println!("nand {}: {}", name, v))
        .share()
        .box_it_clone()
}

fn flipflop(s: ObservableType, r: ObservableType) -> (ObservableType, ObservableType) {
    // Initial state: both outputs start at false (typical SR latch init)
    let s_feedback = Local::behavior_subject::<bool, Infallible>(false);
    let r_feedback = Local::behavior_subject::<bool, Infallible>(false);

    let s_fb_box = s_feedback.clone().box_it_clone();
    let r_fb_box = r_feedback.clone().box_it_clone();

    // Q1 = NAND(S, Q2_feedback)
    let q1 = nand_gate("Q1", s, r_fb_box);

    // Q2 = NAND(R, Q1_feedback)
    let q2 = nand_gate("Q2", r, s_fb_box);

    // Feed Q1 back into S_feedback
    q1.connectable()
        .subscribe_local(Box::new(move |value| {
            s_feedback.next(value);
            Box::new(LocalDisposable::new())
        }))
        .connect()
        .forget();

    // Feed Q2 back into R_feedback
    q2.connectable()
        .subscribe_local(Box::new(move |value| {
            r_feedback.next(value);
            Box::new(LocalDisposable::new())
        }))
        .connect()
        .forget();

    (q1.box_it_clone(), q2.box_it_clone())
}

fn main() {
    let s = Local::behavior_subject::<bool, Infallible>(true);
    let r = Local::behavior_subject::<bool, Infallible>(true);

    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    q1.combine_latest(q2, |q1_v, q2_v| (q1_v, q2_v))
        .subscribe(|(q1_v, q2_v)| {
            println!("Output: (q1={}, q2={})", q1_v, q2_v);
