fn resolve_ref(base_path: &Path, ref_value: &Value) -> Result<Value, String> {
    let ref_str = match ref_value {
        Value::String(s) => s.clone(),
        _ => return Err("Invalid ref type".to_string()),
    };

    let mut parts = ref_str.split('#');
    let file_path_str = parts.next().ok_or("Invalid ref format")?;
    let fragment = parts.next().unwrap_or("");

    let file_path = base_path.join(file_path_str);
    let json_data = fs::read_to_string(&file_path)
        .map_err(|e| format!("Failed to read {}: {}", file_path.display(), e))?;

    let root: Value = serde_json::from_str(&json_data)
        .map_err(|e| format!("Failed to parse {}: {}", file_path.display(), e))?;

    let mut current = &root;
    for part in fragment.split('/').skip(1) {
        if part.is_empty() {
            continue;
        }
        if let Some(new_current) = current.get(part) {
            current = new_current;
        } else {
            return Err(format!("Fragment '{}' not found", part));
        }
    }

    Ok(current.clone())
}

fn resolve_refs_in_value(value: &mut Value, base_path: &Path) -> Result<(), String> {
    match value {
