  "main.rs": "// Shell-style quote-aware tokenizer
// Splits a command line into tokens, respecting single-quoted strings
//
// Rules:
// 1. Outside quotes: whitespace separates tokens
// 2. Inside quotes: everything (including spaces) is preserved
// 3. When a quoted section ends and is immediately followed by unquoted text,
//    they merge into a single token (no separator)

fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_quotes = false;

    for ch in input.chars() {
        match ch {
            '\'' if !in_quotes => {
                // Start of quoted section
                // Push any accumulated unquoted token first
                if !current.trim().is_empty() {
                    tokens.push(current.clone());
                }
                current = String::new();
                in_quotes = true;
            },
            '\'' if in_quotes => {
                // End of quoted section
                in_quotes = false;
                // Don't push token yet - may concatenate with following unquoted text
            },
            ch if in_quotes => {
                // Inside quotes: preserve everything literally
                current.push(ch);
            },
            ch if ch.is_whitespace() => {
                // Whitespace outside quotes: finalize current token
                if !current.trim().is_empty() {
                    tokens.push(current.clone());
                }
                current = String::new();
            },
            _ => {
                // Regular character outside quotes
                current.push(ch);
            },
        }
    }

    // Push any remaining token
    if !current.trim().is_empty() {
        tokens.push(current);
    }

    tokens
}

