        }

        // Allocate shared memory
        let id = shmget(
            libm::SHM_ID,
            size as usize,
            Mode::S_IRWXU | Mode::S_IRGRP | Mode::S_IXGRP,
        ).map_err(|e| format!("Failed to create shm: {:?}", e))?;

        let ptr = unsafe {
            shmat(id, ptr::null_mut(), 0)
                .map_err(|e| format!("Failed to attach shm: {:?}", e))?
        };

        Ok(Self {
            id,
            ptr,
            size,
            running: Arc::new(AtomicBool::new(true)),
        })
    }

    fn write_pixels(&self, pixels: &[u8], width: usize, height: usize, depth: usize) {
        let chunk_size = self.size;
        let mut offset = 0;

        while offset < pixels.len() {
            let remaining = pixels.len() - offset;
            let copy_size = remaining.min(chunk_size - offset.min(chunk_size));

            unsafe {
                std::ptr::copy_nonoverlapping(
                    pixels.as_ptr().add(offset),
                    self.ptr.add(offset % chunk_size),
                    copy_size,
                );
                offset += copy_size;
                if offset % chunk_size == 0 && offset < pixels.len() {
                    // Continue to next page if we're multi-page
                    continue;
                }
            }

            if offset >= pixels.len() {
                break;
            }
        }
    }

    fn cleanup_shm() {
        unsafe {
            let _ = shmctl(libm::SHM_ID, nix::sys::shm::ShmCmd::IPC_RMID);
            if let Some(ptr) = nix::sys::shm::shmat(libm::SHM_ID, ptr::null_mut(), 0).ok() {
                let _ = shmdt(ptr);
            }
        }
    }

    fn unlink_shm(&self) {
        unsafe {
            let _ = shmctl(self.id, nix::sys::shm::ShmCmd::IPC_RMID);
        }
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        unsafe {
            if !self.ptr.is_null() {
                let _ = shmdt(self.ptr);
            }
            self.unlink_shm();
        }
    }
}

fn send_init_command(stdout: &mut impl Write, width: usize, height: usize, id: i32) -> io::Result<()> {
    write!(stdout, \r\"\\x1b_Ga=T,f=24,s={},v={},p={},m=3;\\x1b\\\\\" , width, height, id)?;
    Ok(())
}

fn send_update_command(stdout: &mut impl Write, width: usize, height: usize, id: i32) -> io::Result<()> {
    write!(stdout, \r\"\\x1b_Gm=3,a=D,s={},v={},p={}\\x1b\\\\\" , width, height, id)?;
    Ok(())
}

fn get_terminal_size() -> (usize, usize) {
    match termion::terminal_size_pixels() {
        Ok((width, height)) => (width as usize, height as usize),
        Err(_) => (800, 600), // fallback size
    }
}

fn generate_frame(width: usize, height: usize, time: f32) -> Vec<u8> {
    let mut pixels = Vec::with_capacity(width * height * 3);

    for y in 0..height {
        for x in 0..width {
            let fx = x as f32 / width as f32;
            let fy = y as f32 / height as f32;

            let r = ((fx * std::f32::consts::PI + time).sin() * 0.5 + 0.5) * 255.0;
            let g = ((fy * std::f32::consts::PI + time * 1.3).sin() * 0.5 + 0.5) * 255.0;
            let b = (((fx + fy) * std::f32::consts::PI + time * 0.7).sin() * 0.5 + 0.5) * 255.0;

            pixels.extend_from_slice(&[
                r as u8,
                g as u8,
                b as u8
            ]);
        }
    }

    pixels
}

fn main() {
    let mut stdout = io::stdout();
    let stdout_lock = stdout.lock();
    let mut handle = &mut stdout_lock;

    let (width, height) = get_terminal_size();
    let depth = 3; // RGB
    let pixel_data_size = width * height * depth;

    println!("Initializing Kitty Graphics Protocol with shared memory...");
    println!("Terminal size: {}x{}, Pixel data size: {} bytes", width, height, pixel_data_size);

    // Create shared memory buffer
    let shm_buffer = match ShmBuffer::new(width, height, depth) {
        Ok(buf) => buf,
        Err(e) => {
