            eprintln!("Falling back to base64...");
            return fallback_base64_animation(&mut handle, width, height);
        }
    };

    let running = shm_buffer.running.clone();

    // Set up Ctrl+C handler
    ctrlc::set_handler(move || {
        println!("\nShutting down...");
        running.store(false, Ordering::SeqCst);
    }).expect("Error setting Ctrl-C handler");

    // Send initial command to kitty
    if let Err(e) = send_init_command(handle, width, height, shm_buffer.id) {
        eprintln!("Failed to send init command: {}", e);
        return;
    }

    let mut time: f32 = 0.0;
    let mut last_update = Instant::now();

    println!("Starting animation loop (Ctrl+C to exit)...");

    while running.load(Ordering::SeqCst) {
        let now = Instant::now();

        // Generate frame
        let pixels = generate_frame(width, height, time);

        // Update shared memory buffer
        shm_buffer.write_pixels(&pixels, width, height, depth);

        // Notify kitty to read from shared memory
        if let Err(e) = send_update_command(handle, width, height, shm_buffer.id) {
            eprintln!("Failed to send update command: {}", e);
            break;
        }

        handle.flush().unwrap();

