  "main.rs": "// This demo shows how to maintain span parent-child relationships
// across async boundaries in a multi-stage async workflow.
// Key technique: Store SpanRef and use .entered() guards to rehydrate

use std::sync::Arc;
use tokio::time::{sleep, Duration};
use tracing::{span, Level, Span};
use tracing_subscriber;
use tracing_opentelemetry::OpenTelemetrySpanExt;
use opentelemetry::{trace as otel_trace, KeyValue};
use opentelemetry_sdk::trace as otel_sdk_trace;
use std::time::Duration as StdDuration;

/// Common context that carries trace information across stages
#[derive(Clone)]
pub struct RequestContext {
    /// Reference to the parent request span
    pub request_span: Option<tracing_core::SpanRef>,
}

impl RequestContext {
    fn new(span_ref: tracing_core::SpanRef) -> Self {
        Self {
            request_span: Some(span_ref),
        }
    }
}

/// Trait representing different stages of request processing
pub trait RequestStages {
    async fn stage_1(&self, ctx: &RequestContext);
    async fn stage_2(&self, ctx: &RequestContext);
    async fn upstream_call(&self, ctx: &RequestContext);
}

/// Implementation of the stages
pub struct StageHandler;

#[async_trait::async_trait]
impl RequestStages for StageHandler {
    async fn stage_1(&self, ctx: &RequestContext) {
        // Rehydrate parent span before creating child span
        if let Some(parent_ref) = ctx.request_span.as_ref() {
            let _guard = parent_ref.enter();
        }

        let stage_span = span!(Level::INFO, "stage-1", parent: ctx.request_span.clone());
        drop(stage_span.in_scope(|| {
            tracing::info!("Stage 1 started");
        }));
        sleep(Duration::from_millis(50)).await;
    }

    async fn stage_2(&self, ctx: &RequestContext) {
        // Rehydrate parent span before creating child span
        if let Some(parent_ref) = ctx.request_span.as_ref() {
            let _guard = parent_ref.enter();
        }

        let stage_span = span!(Level::INFO, "stage-2", parent: ctx.request_span.clone());
        drop(stage_span.in_scope(|| {
            tracing::info!("Stage 2 started");
        }));
        sleep(Duration::from_millis(50)).await;
    }

    async fn upstream_call(&self, ctx: &RequestContext) {
        // Rehydrate parent span before creating child span
        if let Some(parent_ref) = ctx.request_span.as_ref() {
            let _guard = parent_ref.enter();
        }

        let upstream_span = span!(Level::INFO, "upstream-call", parent: ctx.request_span.clone());
        drop(upstream_span.in_scope(|| {
            tracing::info!("Upstream call started");
        }));
        sleep(Duration::from_millis(50)).await;
    }
}

/// Simulates calling stages at different times/threads
async fn process_request(handler: &StageHandler, ctx: Arc<RequestContext>) {
    let ctx1 = ctx.clone();
    let ctx2 = ctx.clone();
    let ctx3 = ctx.clone();

    // Stage 1 - might run on any executor location
    handler.stage_1(&ctx1).await;

    // Simulate async yield/thread switch
    sleep(Duration::from_millis(10)).await;

    // Stage 2 - different execution point
    handler.stage_2(&ctx2).await;

    // Upstream - potentially even more delayed
    sleep(Duration::from_millis(10)).await;
    handler.upstream_call(&ctx3).await;
}

#[tokio::main]
async fn main() {
    // Initialize OpenTelemetry SDK
    let tracer = opentelemetry_stdout::SpanExporter::default()
        .with_batch_config_builder(
            opentelemetry_sdk::trace::BatchConfig::default(),
        )
        .build();

    let tracer_provider = opentelemetry_sdk::trace::TracerProvider::builder()
        .with_simple_exporter(tracer)
        .with_resource(opentelemetry_sdk::Resource::new(vec![KeyValue::new(
            "service.name",
            "pingora-tracing-demo",
        )]))
        .build();

    let tracer = tracer_provider.tracer("pingora");

    // Initialize tracing subscriber with OpenTelemetry layer
    let telemetry = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(telemetry)
        .with(tracing_subscriber::fmt::layer().pretty())
        .init();

    // Create the root request span
    let request_span = span!(Level::INFO, "request", request_id = "abc123");

    // Get a reference that can be cloned and passed around
    let span_ref = request_span.span_ref().clone();

    // Create context with the span reference
    let ctx = Arc::new(RequestContext::new(span_ref));

    // Enter the parent span to start recording
    let _guard = ctx.request_span.as_ref().unwrap().enter();

    tracing::info!("Processing request abc123");

    // Run the stages through our handler
    let handler = StageHandler;
    process_request(&handler, ctx).await;

    tracing::info!("Request completed");

    // Drop the span explicitly to ensure it's recorded
    drop(request_span);

    // Shutdown the tracer provider to flush remaining data
    tracer_provider.shutdown().expect("Failed to shutdown tracer provider");
}"
}

