  "main.rs": "use std::task::{Context, Poll};
use futures::{Future, ready};
use std::pin::Pin;

/// Result of attempting to poll a future once
enum TryPollResult<X> {
    /// The future completed successfully
    Ready(X),
    /// The future is still pending
    Pending,
}

/// Attempts to poll a future once in a non-async context
/// 
/// Returns `Ready(value)` if the future completes without needing a waker.
/// Returns `Pending` if the future needs more time (and will continue when awaited).
pub fn try_poll<F, X>(future: &mut Pin<F>) -> TryPollResult<X>
where
    F: Future<Output = X>,
{
    // Create a dummy waker that does nothing - we don't want to register for updates yet
    let waker = futures::task::noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

async fn slow_future() -> i32 {
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
    42
}

async fn instant_future() -> String {
    "instant".to_string()
}

#[tokio::main]
async fn main() {
    println!("=== Testing immediate completion ===");
    {
        let mut f = Pin::new(Box::pin(instant_future()));
        match try_poll(&mut f) {
            TryPollResult::Ready(value) => {
                println!("✓ Got immediate value: {}", value);
            },
            TryPollResult::Pending => {
                println!("✗ Should have been ready immediately");
            }
        }
    }

    println!("\n=== Testing delayed completion ===");
    {
        let mut f = Pin::new(Box::pin(slow_future()));
        match try_poll(&mut f) {
            TryPollResult::Ready(value) => {
                println!("✗ Should have been pending, got: {}", value);
            },
            TryPollResult::Pending => {
                println!("✓ Correctly detected as pending");
                // Now await it in a spawned task
                let result = f.await;
                println!("✓ Later awaited value: {}", result);
            }
        }
    }

    println!("\n=== Reusing same future ===");
    {
        let mut f = Pin::new(Box::pin(async {
            tokio::time::sleep(tokio::time::Duration::from_millis(0)).await;
            100
        }));

        // First poll - might be ready immediately depending on scheduler
        match try_poll(&mut f) {
            TryPollResult::Ready(value) => {
                println!("First poll was ready: {}", value);
            },
            TryPollResult::Pending => {
                println!("First poll was pending");
            }
        }

        // Second poll - should be ready now
        match try_poll(&mut f) {
            TryPollResult::Ready(value) => {
                println!("Second poll is ready: {}", value);
            },
            TryPollResult::Pending => {
                println!("Still pending after second poll");
                let result = f.await;
                println!("Final awaited value: {}", result);
            }
        }
    }

    println!("\nAll tests completed!");
}",
  "notes": "Key points:
1. Uses noop_waker() to poll without registering for notifications
2. Future must be pinned (Pin<Box<>>) for repeated polling
3. Safe to call poll multiple times before awaiting
4. Can branch based on Ready/Pending status
5. No unsafe code required"
