// Custom event handler to remove trailing whitespace before '.' or ',' and position cursor correctly
fn make_handler(handler: WhitespaceHandler) -> Box<dyn rustymap::dyn::FnMut(&Event, u32, bool, &EventContext<'_>)->Option<Cmd>+Send> {
    let insert_char = handler.insert_char;
    Box::new(move |_event: &Event, _count: u32, _positive: bool, context: &EventContext| {
        let pos = context.pos();
        let line = context.line();

        // Find last non-whitespace character before current position
        let trimmed_end = line[..pos].trim_end();
        let non_ws_pos = trimmed_end.len();

        if non_ws_pos < pos {
            // Delete whitespace from non_ws_pos to pos
            let delete_cmd = Cmd::DeleteWhitespace(Movement::BackwardChar((pos - non_ws_pos) as u32));

            // Insert our character after the deleted whitespace
            let insert_cmd = Cmd::InsertChar(insert_char);

            // We'll need to perform these sequentially - insert the char
            Some(delete_cmd)
        } else {
            // No whitespace to delete, just insert normally
            Some(Cmd::InsertChar(insert_char))
        }
    })
