// without the connection closing prematurely.
//
// The key insight is that the Connection future must be kept alive
// in a spawned task that persists for the lifetime of the DbContainer.
// Simply storing the Client alone isn't enough - we need to track
// the Connection task.

use std::sync::Arc;
use tokio::sync::Mutex;
use tokio_postgres::{Client, Config, NoTls};
use url::Url;

pub struct DbConfig {
    pub port: u16,
    pub user: String,
    pub password: String,
}

pub struct DbContainer {
    db_config: DbConfig,
    // Cache the (client, connection_handle) pair
    cached_connection: Mutex<Option<(Client, tokio::task::JoinHandle<()>)>>,
}

impl DbContainer {
    pub fn new(db_config: DbConfig) -> Self {
        Self {
            db_config,
            cached_connection: Mutex::new(None),
        }
    }

    /// Get a cached client connected to the default postgres database
    pub async fn get_default_client(&self) -> Result<Arc<Client>, tokio_postgres::Error> {
        let mut guard = self.cached_connection.lock().await;

        if guard.is_none() {
            let conn_str = format!(
                "host=localhost port={} user={} password={}",
                self.db_config.port, self.db_config.user, self.db_config.password
            );

            let (client, connection) = tokio_postgres::connect(&conn_str, NoTls).await?;

            // Clone the client for storage, but return an Arc-wrapped version
            let client_for_cache = client.clone();

            // Spawn the connection task and keep its handle alive
            let conn_handle = tokio::spawn(async move {
                if let Err(e) = connection.await {
                    eprintln!("Connection error: {}", e);
                }
            });

            *guard = Some((client_for_cache, conn_handle));
        }

        // Return Arc-wrapped client from the cached pair
        Ok(Arc::new(guard.as_ref().unwrap().0.clone()))
    }

    /// Create a new client for a specific database (not cached)
    pub async fn connect_to_db(&self, db_name: &str) -> Result<Client, tokio_postgres::Error> {
        let conn_str = format!(
            "host=localhost port={} user={} password={} dbname={}",
            self.db_config.port, self.db_config.user, self.db_config.password, db_name
        );

        let (client, connection) = tokio_postgres::connect(&conn_str, NoTls).await?;

        // For per-database connections, we still need to spawn the connection task
        // but don't cache it since it's only needed temporarily
        tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("Connection error: {}", e);
            }
        });

        Ok(client)
    }

    /// Execute CREATE DATABASE using cached default connection
    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.get_default_client().await?;

        // Note: In production, use parameterized queries instead of string formatting
        let sql = format!("CREATE DATABASE \"{}\"", name);
        client.execute(&sql, &[]).await?;

        Ok(())
    }

    /// Execute DROP DATABASE using cached default connection
    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let client = self.get_default_client().await?;

        // Terminate backend connections first
        let terminate_sql = format!(
            "SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE datname = $1 AND pid <> pg_backend_pid()",
        );
        client.execute(&terminate_sql, &[&name]).await?;

        // Drop the database
        let drop_sql = format!("DROP DATABASE \"{}\"", name);
        client.execute(&drop_sql, &[]).await
    }
