use std::{collections::HashSet, sync::Arc};
use futures::{SinkExt, StreamExt};

#[derive(Clone)]
struct AppState {
    allowed_origins: Arc<HashSet<String>>,
}

impl Default for AppState {
    fn default() -> Self {
        Self {
            allowed_origins: Arc::new(HashSet::from([
                "https://www.example.com".to_string(),
                "http://localhost:3000".to_string(),
                "https://www.example.com".to_string(),
            ])),
        }
    }
}

async fn client_handler(
    ws: WebSocketUpgrade,
    State(state): State<AppState>,
    request: Request<()>,
) -> impl IntoResponse {
    let origin = request
        .headers()
        .get("origin")
        .and_then(|v| v.to_str().ok())
        .map(String::from);

    if let Some(ref origin) = origin {
        if !state.allowed_origins.contains(origin.as_str()) {
            return format!("Forbidden: Origin '{}' not allowed\n", origin).into_response();
        }
        tracing::info!("Accepted WebSocket connection from origin: {}", origin);
    } else {
        tracing::warn!("Received WebSocket request without Origin header");
        return "Forbidden: Missing Origin header\n".into_response();
    }

    ws.on_upgrade(|socket| handle_socket(socket)).await
}

async fn handle_socket(mut socket: WebSocket) {
    while let Some(result) = socket.next().await {
        match result {
            Ok(msg) => {
                if msg.is_close() {
                    break;
                }
                println!("Received message from client: {}", msg);
                if socket.send(msg).await.is_err() {
                    break;
                }
            }
            Err(err) => {
                eprintln!("Error on WebSocket connection: {:?}", err);
                break;
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let app_state = AppState::default();

    let app = Router::new()
        .route("/client/:session_id", get(client_handler))
        .layer(tower_http::cors::CorsLayer::new()
            .allow_origin("https://www.example.com".parse::<tower_http::cors::AllowOrigin>().unwrap())
            .allow_methods(vec!["GET", "POST"]))
        .with_state(app_state);

    println!("Server listening on http://127.0.0.1:3000");
    println!("Valid origins: {:?}", app_state.allowed_origins.iter());
    println!("Test with: wscat -c 'ws://localhost:3000/client/abc123' --header 'Origin: https://www.example.com'");

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000").await.unwrap();
