    fn complete(
        &self,
        line: &str,
        _pos: usize,
        _ctx: &(),
    ) -> (usize, Vec<Pair>) {
        // Get the last word being typed
        let start_of_last_word = line.rfind(char::is_alphanumeric).map_or(0, |i| i + 1);
        let prefix = &line[start_of_last_word..];

        let mut entries = vec![];

        // Try reading from current directory
