pub fn DragProvider(children: Element) -> Element {
    // Initialize context provider with DragState
    // This makes DragState available to all children
    let _ = use_context_provider(|| DragState::new());

    // Retrieve state from context to use in handlers
    // Note: In some versions, accessing context immediately after setting it
    // requires care, but this pattern generally works in 0.5
    let drag_state = use_context::<DragState>()
        .ok_or("DragState not found")
