        .expect("DragProvider not found");

    let mouse_coords = drag_state.mouse_position;
    let mouse_is_dragged = drag_state.is_dragged;

    // Sync logic: If globally dragging AND this specific point is grabbed, update position
    // This re-renders only when signals change
    if *isDragged.read() && *mouse_is_dragged.read() {
        let m = mouse_coords.peek(); // peek is non-reactive read
        // Only update if position actually changed to minimize diffs
        if coords.peek().x != m.x || coords.peek().y != m.y {
            coords.set(m);
        }
    } else if !*mouse_is_dragged.read() {
