    // This is a unary operator (takes 1 argument).
    let my_sqrt_plus_one = Op::unary(|val: f64| val.sqrt() + 1.0);

    // 2. Configure the tree generation store.
    // We include our custom operator alongside the predefined ones.
    // Note: We cast the closure to match expected traits (Send + Sync)
    let store = vec![
