    // so the GP algorithm should discover our custom operator.
    let mut xs = Vec::new();
    let mut ys = Vec::new();

    for i in 0..50 {
        let x = (i as f64) * 0.1;
        let y = x.sqrt() + 1.0;
        xs.push(x);
        ys.push(y);
