{
  "Cargo.toml": "[package]
name = "rustyline-child-repl"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "14."
crossbeam-channel = "0.5"",
  "main.rs": "// This example demonstrates attempting to host a 'child' output stream
// alongside a rustyline-based REPL.
//
// CRITICAL NOTE: rustyline's `readline()` is synchronous and takes exclusive
// control of the terminal (RAW mode). While a child thread CAN write to stdout,
// doing so while rustyline is waiting for input will disrupt the prompt rendering
// and history navigation visually. For robust async REPL experiences, consider
// `tokio` based terminals (e.g. crossterm/tui) or specialized async readline libs.
//
// This code optimizes the provided architecture to process output *before*
// prompting as much as possible.

use crossbeam_channel::bounded;
use rustyline::Editor;
use std::thread;
use std::time::{Duration, Instant};

fn main() {
    // Channel to receive output from the 'child process' (simulated thread)
    let (tx, rx): (bounded<String>, bounded<String>) = bounded(32);

    // Simulate a child process running in a separate thread
    thread::spawn(move || {
        let mut i = 0;
        loop {
            let msg = format!("[Child] Computation update #{}", i);
            // Try to send to parent; ignore errors if queue full or dropped
            let _ = tx.send(msg);
            i += 1;
            // Simulate work duration
            thread::sleep(Duration::from_millis(500));
        }
    });

    let mut rl: Editor<()> = Editor::new().expect("Could not create Editor");
    let mut history_count = 0;

    println!("Starting REPL. Watch for child output below. Type 'exit' to quit.\n");

    loop {
        // 1. Consume ALL pending messages from the child BEFORE prompting.
        // This keeps the UI cleaner, though it won't help if output happens
        // WHILE the user is typing.
        while let Ok(line) = rx.try_recv() {
            println!("{}", line);
        }

        // 2. Read input (BLOCKING)
        match rl.readline("> ") {
            Ok(input) => {
                // Store in history
                let _ = rl.add_history_entry(input.as_str());

                // Simple command parsing
                let trimmed = input.trim();
                match trimmed {
                    "exit" | "quit" => {
                        println!("Exiting...");
                        break;
                    },
                    "clear" => {
                        // Attempt to clear screen (may interfere with previous output)
                        // rl.move_end_of_line()?; 
                        // Just printing newlines is safer here given TTY conflicts
                        for _ in 0..5 { println!(""); }
                    },
                    "help" => {
                        println!("Commands: exit, help, clear");
                    },
                    _ => {
                        println!("Command received: {}. Ignoring.", trimmed);
                    }
                }
            },
            Err(_) => {
                // Handle EOF or Ctrl+C gracefully
                eprintln!("Input error or interrupted");
            }
        }
    }

    // Save history
    if let Err(e) = rl.save_history("history.txt") {
        eprintln!("Could not save history: {}", e);
    }
}" }

