/// Main function to rewrite imports in a Rust source file.
pub fn rewrite_imports(source: &str) -> String {
    let parsed = ast::SourceFile::parse(source);
    let root = parsed.tree().syntax_node();

    // Collect all use items first (before modifying)
    let mut use_items: Vec<ast::Use> = vec![];
    for node in root.preorder() {
        if let Some(use_item) = ast::Use::cast(node.clone()) {
            use_items.push(use_item);
        }
    }

    // Process each use item
    for use_item in use_items {
        if let Some(tree) = use_item.use_tree() {
            rewrite_use_tree(&tree, None);
        }
    }

    // Return the modified source code
    root.to_string()
}

/// Recursively rewrite paths in a use tree.
/// Keeps track of parent path to build full qualified path.
fn rewrite_use_tree(tree: &ast::UseTree, parent_path: Option<&str>) {
    // Build the current full path based on parent + current segment
    let current_segment = tree.path().and_then(|p| p.segment()).map(|s| s.text());

    let full_path = match (&parent_path, current_segment.as_deref()) {
        (Some(parent), Some(segment)) => format!("{}::{segment}", parent),
        (_, Some(segment)) => segment.to_string(),
        _ => return,
    };

    // Check if this path matches our pattern (contains vexide::devices)
    if should_rewrite_path(&full_path) {
        rewrite_path(tree, &full_path);
    }

    // Get the new path name after rewriting for children
    let new_parent = get_new_path_name(&full_path);

    // Recurse into nested use trees if present
    if let Some(list) = tree.use_tree_list() {
        for sub_tree in list.use_trees() {
            rewrite_use_tree(&sub_tree, Some(&new_parent));
        }
    }
}

/// Determine if a path should be rewritten based on the pattern.
fn should_rewrite_path(path: &str) -> bool {
    path.contains("vexide::devices") || path.starts_with("vexide::devices")
}

/// Rewrite the path by removing "devices" from the middle of vexide paths.
fn rewrite_path(tree: &ast::UseTree, current_path: &str) {
    // Skip wildcard imports - we still need to rewrite them but differently
    if tree.star_token().is_some() {
        // For wildcards like `vexide::devices::*`, we change to `vexide::*`
        if let Some(new_path_str) = get_new_path_string(current_path) {
            if let Some(path) = tree.path() {
                *path = ra_ap_syntax::ast::make::path_from_str(&new_path_str);
            }
        }
        return;
    }

    if let Some(path) = tree.path() {
        let new_path_str = get_new_path_string(current_path);
        *path = ra_ap_syntax::ast::make::path_from_str(&new_path_str);
    }
}

/// Transform old path to new path by removing "devices" layer.
fn get_new_path_string(old_path: &str) -> Option<String> {
    // Pattern: vexide::devices::... -> vexide::...
    if let Some(start) = old_path.find("vexide::devices") {
        let end = old_path[start + "vexide::devices".len()..].trim_start_matches(':').to_string();
        if start == 0 {
            Some(format!("vexide::{}", end.trim_start_matches(':')))
        } else {
            Some(old_path.replace("vexide::devices", "vexide"))
        }
    } else {
        None
    }
}

/// Helper to compute the new parent path name for child nodes.
fn get_new_path_name(old_path: &str) -> String {
