{
  "Cargo.toml": "[package]
name = "broadcast_shutdown"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
tokio-stream = { version = "0.1", features = ["sync"] }
futures = "0.3"",
  "main.rs": "// This example demonstrates how to gracefully shutdown a BroadcastStream 
// even when the Sender is cloned widely across the application.
//
// Problem: Simply dropping a cloned Sender does not close the channel 
// if other Sender clones exist in memory (e.g., in other tasks).
// Solution: Introduce a separate shutdown signal (Watch Channel) that 
// propagates to all streams. Streams consume this signal to terminate.

use futures::stream::{StreamExt, Stream};
use std::error::Error;
use tokio::sync::broadcast::{self, Sender, RecvError};
use tokio::sync::watch;

#[derive(Debug, Clone)]
pub struct Event {
    pub msg: String,
}

pub fn events_channel(
    shutdown_tx: watch::Sender<bool>,
) -> (EventSender, EventStreamFactory) {
    // Create the broadcast channel
    let (tx, _) = broadcast::channel::<Event>(20);

    // Store shutdown receiver in the factory so consumers can listen to it
    let shutdown_rx = shutdown_tx.subscribe();

    (
        EventSender { tx: tx.clone() },
        EventStreamFactory { tx, shutdown_rx },
    )
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

pub struct EventStreamFactory {
    tx: Sender<Event>,
    shutdown_rx: watch::Receiver<bool>,
}

impl EventStreamFactory {
    pub fn all_events(
        &self,
    ) -> impl Stream<Item = Result<Event, RecvError>> + Send {
        BroadcastStreamWrapper {
            inner: BroadcastStream::new(self.tx.subscribe()),
            shutdown: self.shutdown_rx.clone(),
        }
    }
}

// Helper stream that merges broadcast reception with a shutdown signal.
// When shutdown becomes true, this stream stops emitting and closes.
struct BroadcastStreamWrapper {
    inner: tokio_stream::wrappers::BroadcastStream<Result<Event, RecvError>>,
    shutdown: watch::Receiver<bool>,
}

impl Stream for BroadcastStreamWrapper {
    type Item = Result<Event, RecvError>;

    fn poll_next(
        self: std::pin::Pin<&mut Self>,
        cx: &mut std::task::Context<'_>,
    ) -> std::task::Poll<Option<Self::Item>> {
        let this = self.get_mut();

        // Check shutdown signal first (non-blocking peek via recv.borrow)
        if *this.shutdown.borrow() {
            return std::task::Poll::Ready(None);
        }

        // Poll the underlying broadcast stream
        match std::pin::Pin::new(&mut this.inner).poll_next(cx) {
            std::task::Poll::Ready(Some(result)) => {
                // If the channel disconnected, treat it as closed
                if result.is_err() {
                    return std::task::Poll::Ready(None);
                }
                std::task::Poll::Ready(Some(result))
            }
            std::task::Poll::Ready(None) => std::task::Poll::Ready(None),
            std::task::Poll::Pending => std::task::Poll::Pending,
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    println!("Starting Event Service...");

    // Create a shutdown signal channel (false initially)
    let (shutdown_tx, _) = watch::channel(false);

    // Initialize channel abstractions
    let (sender, factory) = events_channel(shutdown_tx);

    // Spawn a task to simulate an SSE client listening to events
    let mut stream = factory.all_events();
    let client_handle = tokio::spawn(async move {
        println!("Client connected to stream.");
        while let Some(res) = stream.next().await {
            match res {
                Ok(event) => println!("Received: {}", event.msg),
                Err(_) => {
                    println!("Stream closed due to error/lag/drop.");
                    break;
                }
            }
        }
        println!("Client disconnect.");
    });

    // Simulate sending some events
    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
    sender.send(Event { msg: "Hello".to_string() });
    sender.send(Event { msg: "World".to_string() });
    sender.send(Event { msg: "Goodbye".to_string() });

    // Wait briefly for client to print
    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;

    // TRIGGER SHUTDOWN
    println!("Initiating Shutdown...");
    // Set the shutdown flag to true. All streams listening to this factory
    // will detect this on their next poll and terminate gracefully.
    let _ = shutdown_tx.send(true);

    // Clean up the main senders. Note: Even if we kept sender clones alive elsewhere,
    // the stream above will still exit because the shutdown signal was processed.
    drop(sender);

    // Await client task completion
    client_handle.await?;

    println!("Service shut down complete.");
    Ok(())
}",
}

