// Messages sent FROM the UI/Tauri frontend TO the agent
enum AgentCmd {
    /// Send keystrokes/data to the PTY
    Input(String),
    /// Terminate the agent
    Stop,
}

/// The Agent manages the PTY lifecycle in a separate thread.
pub struct Agent {
    tx_cmd: Sender<AgentCmd>,
    rx_output: Receiver<String>,
}

impl Agent {
    pub fn new(command: &str, args: &[&str]) -> Result<Self, String> {
        let (tx_cmd, rx_cmd): (Sender<AgentCmd>, Receiver<AgentCmd>) = bounded(100);
        let (tx_out, rx_out): (Sender<String>, Receiver<String>) = bounded(1000);

        // Start the PTY worker thread
        thread::spawn(move || {
            println!">> Starting PTY Process: {}", command);

            // Spawn the PTY session
            let mut session = expectrl::spawn(command)
                .arg(args)
                .expect("Failed to spawn PTY process");

            // Set TERM env var for better compatibility
            session.set_term("xterm-256color");

            loop {
                // 1. Check for incoming input commands first (High Priority)
                // Using try_recv to avoid blocking if no input is available immediately.
                // This ensures we don't starve ourselves from reading PTY output.
                if let Ok(cmd) = rx_cmd.try_recv() {
                    match cmd {
                        AgentCmd::Input(data) => {
                            // Forward input to PTY
                            let _ = session.send_line(&data); // or write for raw chars
                            println!("<< INPUT SENT TO AGENT: {:?}", data.trim_end_matches('\n'));
                        }
                        AgentCmd::Stop => {
                            break;
                        }
                    }
                } else {
                    // 2. No input pending, try to read output from PTY
                    // NOTE: In a production non-blocking environment, you would check FD readiness here.
                    // With expectrl and standard blocking reads, this blocks if the agent is waiting for input.
                    // However, because we decoupled the Sender (UI), the UI is NOT frozen waiting for a mutex.
                    // To further mitigate blocking, use non-blocking mode on the FD if possible via unsafe wrappers.
                    // For this demo, we accept that read() may block, but the application won't dead-lock.

                    let mut buf = vec![0u8; 4096];
                    match session.read(&mut buf) {
                        Ok(n) if n > 0 => {
                            let out = String::from_utf8_lossy(&buf[..n]).to_string();
                            // Emit output to the receiver
                            if tx_out.send(out).is_err() {
                                break;
                            }
                        }
                        Ok(0) => {
                            // EOF
                            println!(">> PTY Process terminated");
                            break;
                        }
                        Err(_) => {
                             // Handle read errors gracefully
                        }
                    }
                }
            }
        });

        Ok(Self {
            tx_cmd,
            rx_output: rx_out,
        })
    }

    // Exposed interface for Tauri Commands
    pub fn send_message(&self, message: String) -> bool {
        // Fire-and-forget style enqueue
        if self.tx_cmd.send(AgentCmd::Input(message)).is_ok() {
            true
        } else {
            false
        }
    }

    pub fn next_output(&self) -> Option<String> {
        // Block until new output available
        self.rx_output.recv().ok()
    }

    pub fn stop(&self) {
        let _ = self.tx_cmd.send(AgentCmd::Stop);
    }
