async fn serve_file(path: &str) -> Result<Response<impl hyper::body::Body>, Infallible> {
    // Join with current directory to simulate root
    let resolved_path = PathBuf::from(".").join(path.trim_start_matches('/'));

    if !resolved_path.exists() {
