  "main.rs": "// WARNING: Manually polling futures is an advanced pattern that can break async guarantees.
// Use with caution and only when necessary.

use std::sync::Arc;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};
use futures::FutureExt;
use tokio::time;

#[derive(Clone)]
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

struct DummyWaker(Arc<()>);

unsafe impl RawWakerVTable for DummyWakerVTable {}

static DUMMY_WAKER_VTABLE: RawWakerVTable = RawWakerVTable::new(
    |_| Box::leak(Box::new(DummyWaker(Arc::new(())))) as *const () as *const _,
    |_| {},
    |_| panic!("waking dummy waker means your future expects to be woken!"),
    |_| {},
);

fn try_poll<X, F>(future: &mut F) -> TryPollResult<X>
where
    F: Future<Output = X>,
{
    let dummy = Arc::new(());

    let raw_waker = RawWaker::new(
        &dummy as *const _ as *const (),
        &DUMMY_WAKER_VTABLE,
    );

    let waker = unsafe { Waker::from_raw(raw_waker) };
    let mut cx = Context::from_waker(&waker);

    match future.poll_unpin(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => {
            // Drop the waker reference (it will drop the Arc)
            drop(waker);
            TryPollResult::Pending
        }
    }
}

async fn slow_future() -> i32 {
    time::sleep(time::Duration::from_millis(50)).await;
    42
}

async fn fast_future() -> i32 {
    100
}

#[tokio::main]
async fn main() {
    println!("Testing try_poll with already-ready future:");
    let mut future = fast_future();

    match try_poll(&mut future) {
        TryPollResult::Ready(value) => {
            println!("✓ Ready immediately! Value: {}", value);
        }
        TryPollResult::Pending => {
            println!("✗ Should have been ready!");
        }
    }

    println!("\nTesting try_poll with pending future:");
    let mut future = slow_future();

    match try_poll(&mut future) {
        TryPollResult::Ready(value) => {
            println!("✗ Should not be ready yet! Value: {}", value);
        }
        TryPollResult::Pending => {
            println!("✓ Correctly detected as pending, spawning task...");

            // Spawn task to complete the future
            let result = tokio::spawn(async move {
                future.await
            }).await.unwrap();

            println!("✓ Task completed with value: {}", result);
        }
    }

    println!("\nAll tests passed!");
}"
