// This implementation uses a state-machine approach which is more readable and 
// avoids the complex ownership/joining logic of iterator pipelines.

fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_single_quote = false;

    for ch in input.chars() {
        if ch == '\'' {
            // Toggle single quote state
            in_single_quote = !in_single_quote;
        } else if ch == ' ' && !in_single_quote {
            // Whitespace outside quotes acts as a delimiter
            if !current_token.is_empty() {
                tokens.push(current_token);
                current_token.clear();
            }
        } else {
            // Character belongs to the current token (even if it's whitespace inside quotes)
            current_token.push(ch);
        }
    }

    // Don't forget the last token if the string doesn't end with whitespace
    if !current_token.is_empty() {
        tokens.push(current_token);
    }

    tokens
}

