    fn to_notion_properties(&self) -> HashMap<String, PropertyValue>;
}

// Struct with property metadata
#[derive(Debug, Serialize, Deserialize)]
struct MyUnit {
    #[property(type = "title", name = "Name")]
    pub name: String,

    #[property(type = "url", name = "Icon url")]
    pub icon_url: Option<String>,

    #[property(type = "multi_select", name = "Roles")]
    pub categories: Option<Vec<String>>,
}

impl ToNotionProperties for MyUnit {
    fn to_notion_properties(&self) -> HashMap<String, PropertyValue> {
        let mut properties = HashMap::new();

        // Name field - Title property
        properties.insert(
            "Name".to_string(),
            PropertyValue::Title(vec![RichTextObject {
                plain_text: Some(self.name.clone()),
                text: TextObject { content: self.name.clone() },
            }]),
        );

        // Icon URL field - URL property (only if present)
        if let Some(icon_url) = &self.icon_url {
            properties.insert("Icon url".to_string(), PropertyValue::Url(icon_url.clone()));
        }

        // Categories field - Multi-select property
        if let Some(categories) = &self.categories {
            let multi_select_values: Vec<SelectObject> = categories
                .iter()
                .map(|cat| SelectObject { name: cat.clone() })
                .collect();
            properties.insert("Roles".to_string(), PropertyValue::MultiSelect(multi_select_values));
        }

        properties
    }
}

use serde::{Deserialize, Serialize};

fn main() {
    let unit = MyUnit {
        name: "Project Alpha".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec!["Development".to_string(), "Backend".to_string(), "Rust".to_string()]),
    };

    println!("Original struct:");
    println!("Name: {}", unit.name);
    println!("Icon URL: {:?}", unit.icon_url);
    println!("Categories: {:?}", unit.categories);
    println!();

    let notion_props: HashMap<String, PropertyValue> = unit.to_notion_properties();

    println!("Converted to Notion HashMap:");
    for (key, value) in notion_props {
        match value {
            PropertyValue::Title(items) => {
                for item in items {
                    println!("  {}: Title({:?})", key, item.text.content);
                }
            }
            PropertyValue::Url(url) => println!("  {}: Url({})", key, url),
            PropertyValue::MultiSelect(selects) => {
                let names: Vec<&str> = selects.iter().map(|s| s.name.as_str()).collect();
                println!("  {}: MultiSelect([{}])", key, names.join(", "));
            }
        }
    }

    println!("\n✅ Successfully converted struct to Notion API HashMap format!");
}"
}

