  "main.rs": "use crossbeam_channel::{bounded, Receiver};
use rustyline::Editor;
use std::io::{self, Write};
use std::process::{Command, Stdio};
use std::thread;
use std::time::Duration;

fn main() -> io::Result<()> {
    let (tx, rx): (bounded<String>, Receiver<String>) = bounded(100);

    // Spawn background thread to monitor child process
    let child_handle = thread::spawn(move || {
        let mut child = Command::new("bash")
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()
            .expect("Failed to start bash subprocess");

        let mut stdin = child.stdin.take().unwrap();
        let mut stdout = child.stdout.take().unwrap();
        let mut stderr = child.stderr.take().unwrap();

        // Read stdout
        let reader_thread = thread::spawn({
            let tx_clone = tx.clone();
            move || {
                let mut buf = String::new();
                use std::io::BufRead;
                let reader = BufReader::new(&mut stdout);
                for line in reader.lines() {
                    if let Ok(line) = line {
                        let _ = tx_clone.send(format!("[child] {}", line));
                    }
                }
            }
        });

        // Read stderr
        let err_reader = thread::spawn({
            let tx_clone = tx.clone();
            move || {
                let mut buf = String::new();
                use std::io::BufRead;
                let reader = BufReader::new(&mut stderr);
                for line in reader.lines() {
                    if let Ok(line) = line {
                        let _ = tx_clone.send(format!("[error] {}", line));
                    }
                }
            }
        });

        drop(tx); // Close receiver side
        child.wait()?; // Wait for process to exit
        Ok::<(), io::Error>(())
    });

    let mut rl: Editor<()> = Editor::new()?;
    println!("Started child process. Type 'exit' to quit.");

    let mut command_queue: Vec<String> = Vec::new();

    loop {
        // First, drain any pending output from child BEFORE showing prompt
        while let Ok(output_line) = rx.try_recv() {
            println!("{}", output_line);
        }

        // Then show prompt and read input
        print!("> ");
        io::stdout().flush()?;

        let readline = rl.readline("> ");
        match readline {
            Ok(input) => {
                rl.add_history_entry(input.as_str());

                if input.trim() == "exit" {
                    break;
                } else if !input.is_empty() {
                    // Queue command for child process
                    command_queue.push(format!("{}\n", input));
                }
