use tracing::{info, warn, error};
use tracing_subscriber::{fmt, Layer, registry::{self, Registry}, filter, reload};

fn main() {
    // Create file for file logging
    let file = OpenOptions::new()
        .append(true)
        .create(true)
        .open("logfile.log")
        .expect("Failed to open log file");

