fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== SCEP PKIOperation CMS Decoder Demo ===\n");

    // Simulate receiving PKCS#7 DER encoded content
    // In production, this would come from HTTP POST body
    let sample_pkcs7_data = load_sample_cms_data()?;

    println!("1. Parsing ContentInfo...");
    match parse_content_info(&sample_pkcs7_data) {
        Ok(ci) => {
            println!("   ✓ ContentInfo parsed successfully");
            println!("   Content Type: {:?}", ci.content_type);
            println!("   Content Length: {} bytes\n", ci.content.len());
        }
        Err(e) => {
            eprintln!("   ✗ Failed to parse ContentInfo: {}", e);
            return Err(Box::new(e));
        }
    }

    println!("2. Decoding CMS SignedData using OpenSSL...");
    match parse_signed_data(&sample_pkcs7_data) {
        Ok(cms) => {
            println!("   ✓ CMS data decoded successfully");
            print_cms_summary(&cms)?;
        }
        Err(e) => {
            eprintln!("   ✗ Failed to decode CMS: {}", e);
        }
    }

    println!("\n3. Alternative: Manual DER Parsing with der-parser...");
    match manual_der_parse(&sample_pkcs7_data) {
        Ok(result) => {
            println!("   ✓ Manual DER parsing completed");
            println!("   Found {} certificates", result.cert_count);
            println!("   Found {} signer infos", result.signer_count);
        }
        Err(e) => {
            eprintln!("   Note: Manual parsing error (expected for complex structures): {}", e);
        }
    }

    Ok(())
}

#[derive(Debug)]
struct ContentInfo {
    content_type: String,
    content: Vec<u8>,
}

fn parse_content_info(data: &[u8]) -> Result<ContentInfo, Box<dyn std::error::Error>> {
    use der_parser::asn1_class::Asn1Class;
    use der_parser::ber::Decoder;

    let decoder = Decoder::new(data);
    let mut reader = der_parser::BerReader::decode_ber(decoder)?;

    // Expect SEQUENCE for ContentInfo
    let seq_reader = reader.read_tlv_expect(Asn1Class::UNIVERSAL, der_parser::Tag::Sequence)?;
    let mut seq_reader = der_parser::BerReader::from_der(seq_reader.to_slice())?;

    // Get OID (content type)
    let oid_reader = seq_reader.read_tlv_expect(Asn1Class::UNIVERSAL, der_parser::Tag::ObjectId)?;
    let oid_value = String::from_utf8_lossy(oid_reader.value()).to_string();

    // Get content OCTET STRING
    let octet_reader = seq_reader.read_tlv_expect(Asn1Class::UNIVERSAL, der_parser::Tag::OctetString)?;
    let content = octet_reader.value().to_vec();

    let content_type_map = [
        ("1.2.840.113549.1.7.1", "pkcs7-data"),
        ("1.2.840.113549.1.7.2", "pkcs7-signedData"),
        ("1.2.840.113549.1.7.3", "pkcs7-envelopedData"),
        ("1.2.840.113549.1.7.4", "pkcs7-sigAndEnvelopedData"),
        ("1.2.840.113549.1.7.5", "pkcs7-digestedData"),
        ("1.2.840.113549.1.7.6", "pkcs7-encryptedData"),
    ];

    let content_type_name = content_type_map
        .iter()
        .find(|(id, _)| id == &oid_value)
        .map(|(_, name)| *name)
        .unwrap_or("unknown");

    Ok(ContentInfo {
        content_type: content_type_name.to_string(),
        content,
    })
}

fn parse_signed_data(data: &[u8]) -> Result<Cms, Box<dyn std::error::Error>> {
    let cms = Cms::load_der(data).map_err(|e| {
        format!("Failed to load CMS: {}. Try ensuring data is valid PKCS#7.", e)
    })?;

    // Attempt verification (may fail without private keys/certs)
    let flags = CmsFlags::NOVERIFY | CmsFlags::DETACHED;
    if let Err(_) = cms.verify(None::<&str>, None, Some(flags)) {
        // Verification failure is expected without full chain, that's OK
    }

    Ok(cms)
}

fn print_cms_summary(cms: &Cms) -> Result<(), Box<dyn std::error::Error>> {
    use openssl::stack::Stack;
    use openssl::x509::X509;

    // Get certificates
    let certs: Stack<X509> = cms.certificates();
