fn manual_der_parse(data: &[u8]) -> Result<(String, usize, usize), Box<dyn std::error::Error>> {
    use der_parser::asn1_class::Asn1Class;
    use der_parser::ber::Decoder;

    let decoder = Decoder::new(data);
    let mut reader = der_parser::BerReader::decode_ber(decoder)?;

    let seq_reader = reader.read_tlv_expect(Asn1Class::UNIVERSAL, der_parser::Tag::Sequence)?;
    let mut seq_reader = der_parser::BerReader::from_der(seq_reader.to_slice())?;

    let mut cert_count = 0;
    let mut signer_count = 0;

    // Navigate through ContentInfo structure
    while !seq_reader.is_complete() {
        let tag = seq_reader.tag();
        match tag.number() {
            16 | 17 => { // CERTIFICATE sequence
                cert_count += 1;
            }
            18 => { // SIGNERINFO
                signer_count += 1;
            }
            _ => {}
        }
        seq_reader.next()?;
    }

    Ok(("MANUAL_PARSE_SUCCESS".to_string(), cert_count, signer_count))
}

struct ParseResult {
    cert_count: usize,
    signer_count: usize,
}

