use tokio::sync::mpsc;
use std::sync::Arc;

/// Struct with borrowed string references for zero-copy deserialization
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// Wrapper that owns the String and contains borrowed references into it.
/// This allows sending between tokio::spawn tasks because the wrapper itself
/// is owned and the references are guaranteed valid as long as it exists.
struct BoundedBorrowedData {
    json_string: String,
    _data: *const (), // Phantom marker to prevent compiler issues
    data_ref: Option<MyData<'static>>,
}

impl BoundedBorrowedData {
    /// Creates new wrapper by deserializing JSON with borrowed references.
    /// We use transmute to cheat the lifetime system safely because we own
    /// the string inside this struct.
    fn new(json_string: String) -> Result<Self, serde_json::Error> {
        // Parse with normal Deserialize first
        let parsed: MyData = serde_json::from_str(&json_string)?;

        // Transmute the lifetime - SAFE because:
        // 1. We own json_string in Self
        // 2. data_ref only lives as long as self does
        // 3. No references escape outside this struct
        unsafe {
            let data_static: MyData<'static> = std::mem::transmute(parsed);
            Ok(Self {
                json_string,
                _data: std::ptr::null(),
                data_ref: Some(data_static),
            })
        }
    }

    fn get_data(&self) -> &MyData<'static> {
        self.data_ref.as_ref().expect("Data should exist")
    }
}

// Safe wrapper pattern using a different approach
struct DeserWrapper {
    raw_json: String,
    parsed: Box<MyData<'static>>,
}

impl DeserWrapper {
    fn new(raw_json: String) -> Result<Self, serde_json::Error> {
        // Create the structure where we control both ownership and borrow
        let my_data: MyData = serde_json::from_str(&raw_json)?;

        // SAFETY: We own 'raw_json', so the references point into owned data
        // This is sound because raw_json and parsed live in same struct
        let data_static: MyData<'static> = std::mem::transmute(my_data);

        Ok(Self {
            raw_json,
            parsed: Box::new(data_static),
        })
    }

    fn data(&self) -> &MyData {
        &self.parsed
    }
}

#[tokio::main]
async fn main() {
    // Create channel for demonstration
    let (tx, mut rx) = mpsc::channel::<String>(10);

    // Spawn sender task
    let tx_clone = tx.clone();
    tokio::spawn(async move {
        let json = r#"{
            "data": "hello borrowed",
            "more_data": "world zero copy"
        }"#;
        tx_clone.send(json.to_string()).await.unwrap();
    });

    // Process received data
    while let Some(json_string) = rx.recv().await {
        println!("Received JSON: {}", json_string);

        // Use the safer boxed wrapper approach
        match DeserWrapper::new(json_string) {
            Ok(wrapper) => {
                println!("Successfully deserialized!");
                println!("Wrapped data: {:?}", wrapper.data());

                // Now we can spawn tasks with the wrapper
                // The wrapper owns the string AND the borrowed references
                let result = process_task(Arc::new(wrapper)).await;
                println!("Task result: {:?}", result);
            },
            Err(e) => eprintln!("Deserialization error: {}", e),
        }
    }
}

async fn process_task(wrapper: Arc<DeserWrapper>) -> String {
    // Can access borrowed data across spawn boundary
    // because wrapper owns the underlying string
    let data = wrapper.data();

    // Do async processing here
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;

    format!("Processed: {}, {}", data.data, data.more_data)
