async fn handle_request(req: Request<Incoming>) -> Result<Response<UnsyncBoxBody<Bytes, io::Error>>, Infallible> {
    let path = req.uri().path();
    info!("Received request for: {}", path);

    if *req.method() == Method::GET {
        match File::open(path).await {
            Ok(mut file) => {
