        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];
        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn new(cutoff: f64, nelems: usize) -> Self {
        let mut elems = Vec::with_capacity(nelems);
        for _ in 0..nelems {
            elems.push(B {
                r: vec![rand_val(), rand_val(), rand_val()],
                v: vec![],
                f: vec![],
                nb: Vec::new(),
            });
        }
        A { elems, cutoff }
    }

    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe sequential version - removes unsafe pointer usage
    pub fn build_lists_sequential(&mut self) {
        let nelems = self.get_nelems();

        // Clear all nb vectors first
        for elem in &mut self.elems {
            elem.nb.clear();
        }

        // Each pair checked exactly once, bidirectional update
        for i in 0..nelems {
            for j in (i + 1)..nelems {
                let dist = self.elems[i].criterion(&self.elems[j]);

                if dist < self.cutoff {
                    self.elems[i].nb.push(j);
                    self.elems[j].nb.push(i);
                }
            }
        }
    }

