}
impl DragState {
    fn new() -&gt; DragState {...}
    pub fn drag_start(&amp;mut self, me: MouseEvent, mut is_dragged: Signal&lt;bool&gt;){
        self.drag_origin.set(me.element_coordinates());
        self.drag_delta.set(ZERO);
        is_dragged.set(true);
    }
    fn drag_stop(&amp;mut self, mut is_dragged: Signal&lt;bool&gt;) {  
