#[component]
fn Point(props: PointProps) -> Element {
    let mut coords = use_signal(|| props.initial_pos);
    let mut is_dragged = use_signal(|| false);
    let drag_state = use_context::<DragState>();
    let mouse_coords = drag_state.mouse_position;
    let mouse_dragging = drag_state.is_dragging;

    // Update position when dragging
    if *mouse_dragging.read() && *is_dragged.read() {
        let current_mouse = mouse_coords.peek();
        let old_pos = coords.peek();

        // Only update if position changed significantly
        if (current_mouse.x - old_pos.x).abs() > 1.0 || (current_mouse.y - old_pos.y).abs() > 1.0 {
            coords.set(current_mouse);
        }
    }

