{
  "Cargo.toml": "[package]
name = "kitty-animation"
version = "0.1.0"
edition = "2021"

[dependencies]
nix = "0.27"
termion = "2.0"",
  "main.rs": "use std::io::{self, Write};
use std::time::{Duration, Instant};
use nix::unistd;
use termion::terminal_size_pixels;

const FRAME_RATE: u64 = 60;
const FRAME_DELAY: Duration = Duration::from_secs(1) / FRAME_RATE;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let stdout = io::stdout();
    let mut handle = stdout.lock();

    let (width, height) = terminal_size_pixels().unwrap_or((640, 480));
    let (width, height) = (width as usize, height as usize);
    let pixel_count = width * height;

    // Create shared memory buffer
    let fd = unistd::memfd_create("kitty_animation", 0)?;

    // Get size needed for RGB pixels (3 bytes per pixel)
    let buf_size = pixel_count * 3;

    // Resize the memfd
    unsafe {
        libc::ftruncate(fd.as_raw_fd(), buf_size as _)?;
    }

    // Map into memory
    let mapping = libc::mmap(
        std::ptr::null_mut(),
        buf_size,
        libc::PROT_READ | libc::PROT_WRITE,
        libc::MAP_SHARED,
        fd.as_raw_fd(),
        0,
    );

    if mapping == libc::MAP_FAILED {
        return Err("Failed to mmap".into());
    }

    let mut time: f32 = 0.0;
    let frame_interval = FrameInterval::new(FRAME_DELAY);

    println!("\n\n\nKitty Animation - Press Ctrl+C to exit\n\n");

    loop {
        let now = Instant::now();

        // Generate animated RGB gradient pixel data directly into shared memory
        unsafe {
            for (y_idx, y) in (0..height).enumerate() {
                for (x_idx, x) in (0..width).enumerate() {
                    let fx = x as f32 / width as f32;
                    let fy = y as f32 / height as f32;

                    let r = ((fx * std::f32::consts::PI + time).sin() * 0.5 + 0.5) * 255.0;
                    let g = ((fy * std::f32::consts::PI + time * 1.3).sin() * 0.5 + 0.5) * 255.0;
                    let b = (((fx + fy) * std::f32::consts::PI + time * 0.7).sin() * 0.5 + 0.5) * 255.0;

                    let idx = (y_idx * width + x_idx) * 3;
                    let ptr = mapping.add(idx);
                    *ptr.offset(0) = r as u8;
                    *ptr.offset(1) = g as u8;
                    *ptr.offset(2) = b as u8;
                }
            }
        }

        // Kitty Graphics Protocol shared memory transmission
        write!(handle, "\x1b[H")?;

        // First frame with all parameters
        writeln!(
            handle,
            "\x1b_Gid=1,t=T,a=S,f={},s={},v={},h={},w={},m=0,",
            frame_delay_ms(FRAME_DELAY),
            width,
            height,
            24,
            1,
        )?;

        // Flush to ensure data reaches terminal
        handle.flush()?;

        // Sync the memfd content before next frame
        unsafe {
            libc::msync(mapping, buf_size, libc::MS_SYNC);
        }

        frame_interval.tick(now);

        time += 0.1;
    }
}

struct FrameInterval {
    target: Duration,
    last_frame: Instant,
}

impl FrameInterval {
    fn new(target: Duration) -> Self {
        Self {
            target,
            last_frame: Instant::now(),
        }
    }

    fn tick(&mut self, now: Instant) {
        let elapsed = now - self.last_frame;
        if elapsed < self.target {
            std::thread::sleep(self.target - elapsed);
        }
        self.last_frame = Instant::now();
    }
}

fn frame_delay_ms(duration: Duration) -> u64 {
    duration.as_millis() as u64
}",
}

