/// Resolve $ref in a serde_json::Value by following references to other JSON files
fn resolve_refs(value: &mut serde_json::Value) -> Result<(), String> {
    match value {
        serde_json::Value::Object(map) => {
            // Check if this object is a $ref reference
            if let Some(ref_value) = map.get("$ref") {
                let ref_str = match ref_value.as_str() {
                    Some(s) => s,
                    None => return Err(format!("$ref must be a string: {:?}", ref_value)),
                };

                // Parse the ref: filename#path
                let mut parts = ref_str.split('#');
                let file_path = parts.next().unwrap_or("");
                let json_path = parts.next();

                // Load the referenced file
                let content = fs::read_to_string(file_path)
                    .map_err(|e| format!("Failed to read {}: {}", file_path, e))?;

                let root: serde_json::Value = serde_json::from_str(&content)
                    .map_err(|e| format!("Failed to parse {}: {}", file_path, e))?;

                // Navigate to the path within the JSON document
                let referenced_value = if let Some(path) = json_path {
                    if path.is_empty() || path == "/" {
                        root
                    } else {
                        let mut current = &root;
                        // Split path like #/p_list into tokens and traverse
                        for token in path.split('/').skip(1) {
                            if let Some(Value::Object(obj)) = current.as_object() {
                                current = obj.get(token).ok_or_else(|| {
                                    format!("Path segment '{}' not found", token)
                                })?;
                            } else {
                                return Err(format!("Cannot navigate into non-object"));
                            }
                        }
                        current.clone()
                    }
                } else {
                    root
                };

                *value = referenced_value;
            } else {
                // Recursively process nested objects and arrays
                for (_, v) in map.iter_mut() {
                    resolve_refs(v)?;
                }
                for arr in map.values_mut().filter_map(|v| v.as_array_mut()) {
                    for item in arr {
                        resolve_refs(item)?;
                    }
                }
            }
        }
        serde_json::Value::Array(arr) => {
            for item in arr {
                resolve_refs(item)?;
            }
        }
        _ => {}
    }
    Ok(())
}

fn main() {
    // Step 1: Read b.json as raw JSON Value
    let json_data = fs::read_to_string("b.json").expect("failed to read from b.json");
    let mut value: serde_json::Value = serde_json::from_str(&json_data)
        .expect("failed to parse b.json");

    // Step 2: Resolve any $ref references
    resolve_refs(&mut value).expect("failed to resolve references");

    // Step 3: Deserialize into our struct
    let a_obj: A = serde_json::from_value(value).expect("deserialization failed");

    // Step 4: Print the paths
    for p in &a_obj.path_list {
        println!("{}", p.display());
    }
}"
}
