//! The original code shared `Arc<Mutex<Session>>` between a Read Thread and Write Commands.
//! When `read()` blocked waiting for CLI input, it held the Mutex, preventing `send()` from
//! acquiring the lock. This caused the UI to freeze/hang.
//!
//! ## The Solution
//! 1. **Remove Shared Mutex**: Do not share the `Session` via Mutex between threads.
//! 2. **Single Ownership**: The `Session` is owned exclusively by a dedicated Worker Thread.
//! 3. **Message Passing**: The UI/Tauri Commands push input to a `Sender` channel.
//! 4. **Interleaved Processing**: The Worker Thread processes input messages AND PTY reads in a loop.
//!
//! Note: For perfect interactivity during `read()` waits (e.g., CLI prompting), the PTY FD
//! should ideally be `O_NONBLOCK` and polled via `mio`/`tokio`. `expectrl` is blocking by design.
//! This example solves the Mutex Deadlock; for latency, `read()` timeouts are simulated."
use crossbeam_channel::{unbounded, RecvTimeoutError};
use expectrl::Session;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Arc, mpsc};
use std::thread;
use std::time::Duration;

/// Represents the Agent running in the background
pub struct Agent {
    /// Sender for user input (simulating Tauri IPC)
    tx_input: crossbeam_channel::Sender<String>,
    /// Flag to signal shutdown
    running: Arc<AtomicBool>,
}

impl Agent {
    /// Spawns the agent and initializes the PTY
    pub fn new(command: &str, args: &[&str]) -> Result<Self, String> {
        // 1. Create the PTY Session
        // We pass TERM=xterm-256color to ensure proper rendering expectations
        env::set_var("TERM", "xterm-256color");
        let mut session = Session::new(
            None,
            &format!("{} {}",
            std::process::Command::new(command)
                .args(args)
                .spawn()
                .map_err(|e| e.to_string())?,
            )
        ).map_err(|e| e.to_string())?;

        // 2. Setup Communication Channels
        let (tx_input, rx_input) = unbounded::<String>();
        let (tx_output, rx_output) = mpsc::channel::<String>();
        let running = Arc::new(AtomicBool::new(true));
        let running_clone = running.clone();

        // 3. Spawn Worker Thread
        // This thread OWNS the Session. No other thread accesses it directly.
        thread::spawn(move || {
            println!("[Worker] Agent started");
            loop {
                // --- 1. Check for Input Messages First ---
                // We use a timeout so we don't block waiting for input if none is coming.
                // This allows us to occasionally yield back to read PTY output.
                match rx_input.recv_timeout(Duration::from_millis(10)) {
                    Ok(input_msg) => {
                        // Simulate typing (add newline if needed)
                        let msg_to_send = format!("{}\r", input_msg.trim());
                        let _ = session.send(&msg_to_send);
                        println!("[Worker] Sent to PTY: {:?}", input_msg.trim());
                        continue; // Priority to input
                    }
                    Err(RecvTimeoutError::Timeout) => {}
                    Err(e) => {
                        eprintln!("[Worker] Channel error: {:?}", e);
                        break;
                    }
                }

                // --- 2. Read PTY Output ---
                // If we didn't get input, try to read output.
                // NOTE: In a production app with blocking CLI, consider setting FD to NONBLOCK
                // using libc/fcntl and implementing a custom poll loop here, as expectrl
                // read() is inherently blocking.
                // Here we use a small sleep hack to avoid busy-looping if EOF is hit quickly,
                // but expectrl handles the blocking read natively.

                // Attempt to read. 
                // Because we can't easily make expectrl non-blocking in safe code,
                // we accept that this read may block.
                // However, since NO MUTEX protects this object globally anymore,
                // the INPUT PATH (which calls tx.send) is NEVER blocked by this read.
                // The only cost is input processing delay, not system deadlock.

                let mut buf = [0u8; 1024];
                match session.read(&mut buf) {
                    Ok(n) => {
                        if n == 0 {
                            println!("[Worker] Process exited");
                            break;
                        }
                        let output = String::from_utf8_lossy(&buf[..n]).to_string();
                        // Forward output to main (simulating Tauri emit)
                        let _ = tx_output.send(output);
                    }
                    Err(_) => {
                        // Connection broken or non-blocking mode error (if implemented)
                        println!("[Worker] Read error or EOF");
                        break;
                    }
                }
            }
            running_clone.store(false, Ordering::SeqCst);
        });

        // Return Agent and Output Receiver to caller
        // In Tauri, you would return only the Agent struct and handle emit internally via EventContext
        Ok(Agent {
            tx_input,
            running,
        })
    }

    /// Sends input from the frontend (Tauri Command equivalent)
    pub fn send(&self, message: &str) -> Result<(), String> {
        if !self.running.load(Ordering::SeqCst) {
            return Err("Agent not running".to_string());
        }
        self.tx_input
            .send(message.to_string())
            .map_err(|e| format!("Failed to send message: {:?}", e))
    }
}

// --- Tauri State Simulation ---

struct AppState {
    agent: Option<Agent>,
    // In Tauri, you'd use AppHandle or EventContext to emit events.
    // Here we simulate a listener.
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting Tauri + ExpectRL PTY Demo");
    println!("Running interactive shell...");

    // Initialize State
    let state = AppState {
        agent: Some(Agent::new("sh", &[])?), // Spawn shell
    };

    // Simulate Frontend Interaction
    // Usually this is handled by #[tauri::command] functions triggered by React
    let agent = state.agent.as_ref().unwrap();

    // 1. Initial Echo
    thread::sleep(Duration::from_millis(500));
    agent.send("echo Hello from Rust Backend")?;

    // 2. Wait for output loop
    thread::sleep(Duration::from_millis(500));

    // 3. Interactive Test: Send commands that prompt or produce text
    println!("\n--- Sending 'pwd' ---");
    agent.send("pwd")?;

    println!("\n--- Sending 'whoami' ---");
    agent.send("whoami")?;

    println!("\n--- Waiting 3 seconds to observe output flow ---");
    thread::sleep(Duration::from_secs(3));

    println!("\nDemo finished. Agent remains alive.");
    Ok(())
}
