use tracing::{info, span, Level, Span};
use tokio::task::JoinHandle;

/// Simulates the shared context passed across Pingora stages.
/// We store the `Span` here to allow rehydration in callbacks.
struct RequestContext {
    /// The parent span representing the request lifecycle.
    /// `Span` implements `Send + Sync`, allowing it to be moved across threads.
    parent_span: Span,
}

impl RequestContext {
    fn new(parent_span: Span) -> Self {
        Self { parent_span }
    }

    /// Simulates a Pingora stage function called asynchronously.
    /// This is where we MUST rehydrate the context.
    fn execute_stage(&self, stage_name: &str) -> JoinHandle<()> {
        // Clone the span handle to move it into the async task.
        // This retains a reference to the underlying trace data.
        let parent_handle = self.parent_span.clone();

        // Spawn on a potentially different thread/executor
        tokio::spawn(async move {
            info!("Stage task started: {}", stage_name);

            // --- REHYDRATION LOGIC START ---
            // We use `in_scope` to push the stored span onto the current thread's
            // tracing context stack. Any spans created inside this closure
            // will now be children of `parent_handle`, regardless of where
            // this code executes relative to the original request start.
            parent_handle.in_scope(|| {
                let stage_span = span!(Level::INFO, "stage", name = stage_name);
                let _guard = stage_span.enter();

                // Simulate upstream work or processing
                tokio::time::sleep(std::time::duration::Duration::from_millis(10)).await;
                info!("Stage {} work done", stage_name);
            });
            // --- REHYDRATION LOGIC END ---
        })
    }
}

#[tokio::main]
async fn main() {
    // Initialize OTEL + Tracing pipeline
    setup_tracing();

    // 1. Begin the Request Span (Root)
    let req_span = span!(Level::INFO, "http_request", method = "GET", uri = "/api/v1");
    let _req_guard = req_span.enter();

    info!("Incoming request received");

    // 2. Construct context with the span
    let ctx = Arc::new(RequestContext::new(req_span));

    // 3. Trigger multiple stages (simulating callbacks/dispatched stages)
    let stage1 = ctx.execute_stage("parse_body");
    let stage2 = ctx.execute_stage("validate_auth");
    let stage3 = ctx.execute_stage("call_upstream");

    // 4. Await completion
    let _ = tokio::join!(stage1, stage2, stage3);

    info!("Request completed");

    // Shutdown exporter to ensure all logs are flushed
    opentelemetry::global::shutdown_tracer_provider();
}

fn setup_tracing() {
    // Configure OpenTelemetry SDK to export to stdout (for demo purposes)
    // In production, this would point to an OTLP receiver.
    let exporter = opentelemetry_stdout::SpanExporter::default();
    let provider = opentelemetry_sdk::trace::TracerProvider::builder()
        .with_simple_exporter(exporter)
        .build();

    // Install provider globally
    opentelemetry::global::set_tracer_provider(provider);

    // Get a tracer instance for the application
    let tracer = opentelemetry::global::tracer("pingora-proxy");

    // Attach the OTEL layer to the global tracing subscriber
    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(otel_layer)
        .with(tracing_subscriber::fmt::layer()
            .pretty()
            .with_target(true)
        )
        .init();
}
"
