  "main.rs": "use crossterm::event::{self, Event, KeyCode};
use crossterm::terminal::{disable_raw_mode, enable_raw_mode};
use std::io::{self, Write};
use std::time::{Duration, Instant};

fn main() -> io::Result<()> {
    // Enable raw mode to get low-level event access and avoid buffering/echo issues
    enable_raw_mode()?;
    let mut stdout = io::stdout();

    println!("Starting event loop. Press 'q' to quit.");
    println!("Notice how the 'tick' message appears EVERY SECOND, regardless of input.");

    let mut last_tick = Instant::now();
    let tick_rate = Duration::from_secs(1);

    loop {
        // Calculate how much time remains until the next tick
        let elapsed = last_tick.elapsed();
        let wait = tick_rate.saturating_sub(elapsed);

        // Poll for events with a timeout. 
        // If an event is ready immediately, poll returns Ok(true).
        // If the timeout elapses without an event, poll returns Ok(false).
        if event::poll(wait)? {
            // An event is available, read and handle it immediately
            match event::read()? {
                Event::Key(key) if key.code == KeyCode::Char('q') => {
                    println!("\n'q' pressed, quitting.");
                    break;
                }
                _ => {}
            }
        }

        // Regardless of whether input occurred, check if it's time to tick.
        // This ensures the timer stays accurate even if we spent time handling input.
        if last_tick.elapsed() >= tick_rate {
            println!("Tick!");
            stdout.flush()?;
            last_tick = Instant::now();
        }
    }

    // Restore terminal state
    disable_raw_mode()?;
    Ok(())
}"
}

