  "main.rs": "fn tokenize(s: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_quotes = false;

    for ch in s.chars() {
        match ch {
            '\'' => {
                if !in_quotes {
                    // Closing previous token before quote starts
                    if !current_token.is_empty() && !current_token.chars().all(|c| c == ' ') {
                        tokens.push(current_token.trim().to_string());
                        current_token.clear();
                    }
                    in_quotes = true;
                } else {
                    // Quote ends
                    if !current_token.is_empty() {
                        tokens.push(current_token);
                    }
                    current_token.clear();
                    in_quotes = false;
                }
            },
            ' ' | '\t' | '\n' | '\r' => {
                if in_quotes {
                    current_token.push(ch);
                } else if !current_token.is_empty() && !current_token.chars().all(|c| c == ' ') {
                    tokens.push(current_token.trim().to_string());
                    current_token.clear();
                }
            },
            _ => {
                current_token.push(ch);
            },
        }
    }

    // Handle remaining content
    if !current_token.is_empty() {
        if in_quotes {
            tokens.push(current_token);
        } else if !current_token.chars().all(|c| c == ' ') {
            tokens.push(current_token.trim().to_string());
        }
    }

    tokens
}

fn main() {
    let test_input = " one  ' two  'three    four";

    println!("Input: {:?}", test_input);
    let tokens = tokenize(test_input);
    println!("{} args:", tokens.len());
    for token in &tokens {
        println!("<{}>", token);
    }

    println!();

    // Additional test cases
    assert_eq!(tokenize("'one'  ' two  'three    four"), vec!["one", " two  three", "four"]);
    assert_eq!(tokenize("a b c"), vec!["a", "b", "c"]);
    assert_eq!(tokenize("'hello world'"), vec!["hello world"]);
    assert_eq!(tokenize("   " ), vec![]);

    println!("All tests passed!");
}"
}

