// Represents the 'il' crate containing implementations AND the dispatch wrapper.
// This layer depends on 'al'.
pub mod il {
    use enum_dispatch::enum_dispatch;
    use crate::al::Rest;

    // Concrete implementation A
    pub struct Foo {
        name: &'static str,
    }

    impl Foo {
        pub fn new() -> Self {
            Foo { name: "Foo" }
        }
    }

