        fn disconnect(&self) -> String {
            format!("{} disconnected", self.name)
        }
        fn status(&self) -> i32 {
            1
        }
    }

    impl Rest for Boo {
        fn connect(&self) -> String {
            format!("{} online", self.name)
        }
        fn disconnect(&self) -> String {
            format!("{} offline", self.name)
        }
        fn status(&self) -> i32 {
