    // 'il' knows about the variants (Foo, Boo).
    // 'il' imports the trait from 'al'.
    // 'al' remains unaware of 'il', breaking the cycle.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }

    // Helper constructors to expose functionality in 'bl'
    impl Item {
        pub fn foo() -> Self {
            Item::Foo(Foo::new())
        }

        pub fn boo() -> Self {
            Item::Boo(Boo::new())
        }
    }
}

// --- BL (Business Layer) ---
// Represents the 'bl' crate.
// It depends on 'il' to access the dispatch wrapper.
// It uses 'al' traits indirectly via 'il' exports.
