use std::fmt;

#[derive(Debug)]
pub struct Character {
    pub name: String,
    pub ac: u8,
    pub current: u16,
    pub max: u16,
    pub temp: u16,
}

// Manual implementation of Deserialize allows us to consume one JSON field 
// ('hp') and assign it to two struct fields ('current' and 'max').
impl<'de> Deserialize<'de> for Character {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        use serde::de::{self, MapAccess, Visitor};
        use std::marker::PhantomData;

        struct CharacterVisitor;

        impl<'de> Visitor<'de> for CharacterVisitor {
            type Value = Character;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct Character")
            }

            fn visit_map<V>(self, mut map: V) -> Result<Character, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut name: Option<String> = None;
                let mut ac: Option<u8> = None;
                let mut hp: Option<u16> = None;

                // Iterate through the map fields provided by Serde
                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "name" => name = Some(map.next_value()?),
                        "ac" => ac = Some(map.next_value()?),
                        "hp" => hp = Some(map.next_value()?),
                        _ => { /* Ignore unknown fields */ }
                    }
                }

                let name = name.ok_or_else(|| de::Error::missing_field("name"))?;
                let ac = ac.ok_or_else(|| de::Error::missing_field("ac"))?;
                let hp = hp.ok_or_else(|| de::Error::missing_field("hp"))?;

                // Here we duplicate the 'hp' value into 'current' and 'max', 
                // and set 'temp' to default 0.
                Ok(Character {
                    name,
                    ac,
                    current: hp,
                    max: hp,
                    temp: 0,
                })
            }
        }

        const FIELDS: &[&str] = &["name", "ac", "hp"];
        deserializer.deserialize_struct("Character", FIELDS, CharacterVisitor)
    }
}

fn main() {
    let json = r#"{
        "name": "Henry",
        "ac": 16,
        "hp": 54
    }"#;

    let character: Character = serde_json::from_str(json).expect("Failed to deserialize");

    println!("Name: {}", character.name);
    println!("AC: {}", character.ac);
    println!("Current HP: {}", character.current);
    println!("Max HP: {}", character.max);
    println!("Temp HP: {}", character.temp);
}"
