/// Optimized for 4-byte (RGBA/ABGR) pixels by swapping `u32` values instead of individual bytes.
/// Uses unaligned access to safely handle potential misalignment of the input `&[u8]` slice 
/// relative to `u32` requirements, maximizing performance on AMD64/ARM64 without panic risk.
fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

    let pixel_count = line_bytes.len() / BYTES_PER_PIXEL;
    let half_pixels = pixel_count / 2;

