/// Parses an ISO format date string that may or may not have fractional seconds
fn parse_iso_date_string(d: &str) -> Result<DateTime<Utc>, String> {
    // Try format with fractional seconds first
    if let Ok(dt) = DateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S%.f") {
        return Ok(dt.with_timezone(&Utc));
    }

    // Try format without fractional seconds
    if let Ok(dt) = DateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S") {
        return Ok(dt.with_timezone(&Utc));
    }

    Err(format!("Failed to parse date string: {}", d))
}

/// Converts parsed date time to Unix timestamp (seconds since epoch)
pub fn date_string_to_int(d: &str) -> Result<i64, String> {
    let datetime = parse_iso_date_string(d)?;
    Ok(datetime.timestamp())
}

/// Converts parsed date string directly to chrono::DateTime<Utc>
pub fn date_string_to_datetime(d: &str) -> Result<DateTime<Utc>, String> {
    parse_iso_date_string(d)
}

