    for date_str in test_cases {
        match date_string_to_datetime(date_str) {
            Ok(dt) => {
                let unix_timestamp = dt.timestamp();
                println!("Input:      \"{}\"", date_str);
                println!("DateTime:   {:?}", dt);
                println!("Timestamp:  {}", unix_timestamp);
