// 
// Ordering Question:
// "I feel that Ordering I've used is not correct. What is the correct Ordering and why?"
//
// ANSWER:
// Ordering::Relaxed is CORRECT inside a critical_section::with block.
//
// WHY?
// 1. Atomicity Guarantee: The critical_section mechanism (typically disabling interrupts)
//    ensures that the Load-Modify-Store sequence cannot be interleaved with any interrupt
//    handler or other execution context on the core. This replaces the hardware atomicity
//    provided by fetch_add.
// 2. Memory Ordering: Original fetch_add(Relaxed) guarantees atomicity but does not enforce
//    synchronization of surrounding variables. Since critical_section entry/exit acts as a
//    barrier preventing preemption, using Relaxed internally preserves the original semantic
//    intent without introducing unnecessary compiler/memory fences (Acquire/Release/SeqCst).
// 3. Performance: Stricter orderings (like SeqCst) add unnecessary overhead inside a block
//    that is already serialized by the critical section mechanism.

use core::sync::atomic::{AtomicUsize, Ordering};

struct ChannelManager {
    channel_index: AtomicUsize,
}

impl ChannelManager {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    fn get_next_channel(&self) -> usize {
        // Replacement for self.channel_index.fetch_add(1, Ordering::Relaxed);
        // On embedded (thumbv6m-none-eabi), use the real critical_section crate.
        #[cfg(not(any(target_arch = "thumbv6m", target_arch = "arm")))]
        {
            // MOCK FOR HOST TESTING ONLY (std sync mutex)
            // This ensures `cargo run` works on your PC without embedding toolchains.
            // In your actual embedded project, remove this block and use the #[cfg(embedded)] block below.
            static mut GLOBAL_LOCK: std::sync::Mutex<()> = std::sync::Mutex::new(());
            let _guard = unsafe { GLOBAL_LOCK.lock().unwrap() };

