use tower::layer::Layer;
use tower::Service;
use tracing_subscriber::{fmt, EnvFilter};

// --- Configuration ---
const ALLOWED_ORIGINS: [&str; 1] = ["https://www.example.com"];

// --- Middleware Layer ---
struct OriginFilterLayer;

impl<S> Layer<S> for OriginFilterLayer {
    type Service = OriginFilterService<S>;

    fn layer(&self, inner: S) -> Self::Service {
        OriginFilterService { inner }
    }
}

struct OriginFilterService<S> {
    inner: S,
}

impl<S> Service<Request<Body>> for OriginFilterService<S>
where
    S: Service<Request<Body>, Response = Response> + Clone + Send + 'static,
    S::Future: Send + 'static,
    S::Error: Into<Infallible> + 'static, // Assuming infallible or mapping to it for simplicity in demo
{
    type Response = Response;
    type Error = Box<dyn std::error::Error + Send + Sync>;
    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>;

    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        self.inner.poll_ready(cx).map_err(|e| e.into())
    }

    fn call(&mut self, req: Request<Body>) -> Self::Future {
        // Check Origin header
        let headers = req.headers();
        let origin_opt = headers.get("origin");

        // If Origin header is present, validate it
        if let Some(origin_val) = origin_opt {
            let origin_str = match origin_val.to_str() {
                Ok(s) => s,
                Err(_) => {
                    // Invalid UTF8 in origin
                    return ready_error_response(StatusCode::FORBIDDEN);
                }
            };

            let allowed = ALLOWED_ORIGINS.contains(&origin_str);

            // If we are dealing with a WebSocket Upgrade, strict check is crucial.
            // Headers for upgrade: "connection": "Upgrade", "upgrade": "websocket"
            let is_ws = headers.get("upgrade")
                .map(|v| v.to_str().unwrap_or_default().to_lowercase() == "websocket")
                .unwrap_or(false);

            if !allowed && (is_ws || origin_str.starts_with("http")) {
                // Reject invalid origins, especially for websockets
                return ready_error_response(StatusCode::FORBIDDEN);
            }
        }

        // If check passes (or was skipped), proceed to inner service
        let inner_fut = self.inner.call(req);
        // Map inner future output to our expected Future type
        Box::pin(async move {
            match inner_fut.await {
                Ok(res) => Ok(res),
                Err(e) => Err(Box::new(e) as Box<dyn std::error::Error + Send + Sync>),
            }
        })
    }
}

fn ready_error_response(status: StatusCode) -> Pin<Box<dyn Future<Output = Result<Response, Box<dyn std::error::Error + Send + Sync>>> + Send>> {
    Box::pin(async move {
        Ok(
            Response::builder()
                .status(status)
                .body(Body::from(format!("Status {}: Access Denied", status)))
                .expect("Cannot build response")
        )
    })
}

// --- Helper for WebSockets ---
async fn ws_handler(req: Request<Body>) -> Result<impl IntoResponse, StatusCode> {
