    tracing_subscriber::fmt()
        .with_env_filter(EnvFilter::from_default_env().add_directive("axum=info".parse().unwrap()))
        .init();

    let app = Router::new()
        .route("/ws", get(ws_handler))
        .layer(OriginFilterLayer) // <-- Apply Origin Filter here
        .fallback(get(|| async { "Hello, World!" }));

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
    tracing::info!("Server listening on 0.0.0.0:3000");
    tracing::info!("Allowed Origin: {:?}", ALLOWED_ORIGINS);
    tracing::info!("Try connecting with: curl -H \"Origin: https://www.example.com\" -H \"Connection: Upgrade\" -H \"Upgrade: websocket\" http://localhost:3000/ws");

    axum::serve(listener, app).await.unwrap();
