    let mut ctrl_c = signal::ctrl_c();
    tokio::pin!(ctrl_c);

    // Wait for Ctrl+C or server error
    tokio::select! {
        _ = &mut *ctrl_c => {
            info!("\nReceived Ctrl+C - initiating graceful shutdown...");
        }
        result = &mut *server_future => {
            if let Err(e) = result {
                warn!("Server stopped due to error: {}", e);
            }
        }
    }

    // Signal shutdown to all components
    should_shutdown.store(true, Ordering::SeqCst);

    // Stop the HTTP server gracefully (allow existing connections to finish)
    server_future.stop(true).await;

    // Wait for queue handler to finish its current work
    match queue_task.await {
