  "main.rs": "use std::io::{self, Stdin};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;
use std::time::Duration;
use crossbeam_channel::{Receiver, Sender, try_send, select};
use signal_hook::{consts::{SIGINT, SIGTERM}, iterator::Signals};
use termion::raw::IntoRawMode;

// Message enum for different events
#[derive(Debug, Clone)]
enum Message {
    Key(char),
    Signal(i32),
    Shutdown,
}

// Shared state for graceful shutdown
struct SharedState {
    sender: Sender<Message>,
    shutdown_flag: Arc<AtomicBool>,
}

impl SharedState {
    fn new(sender: Sender<Message>) -> Self {
        Self {
            sender,
            shutdown_flag: Arc::new(AtomicBool::new(false)),
        }
    }
}

fn yield_signals(state: &SharedState) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).expect("Failed to set up signal handler");
    let sender = &state.sender;

    for sig in signals.forever() {
        if state.shutdown_flag.load(Ordering::SeqCst) {
            break;
        }

        match sig {
            SIGINT | SIGTERM => {
                let _ = try_send(sender, Message::Signal(sig));
                // Don't continue - exit on first signal
                break;
            }
            _ => {}
        }
    }
}

fn yield_keys(state: &SharedState) {
    let mut stdout = io::stdout().into_raw_mode().unwrap();
    let mut stdin = io::stdin().lock();
    let sender = &state.sender;

    loop {
        // Check shutdown flag
        if state.shutdown_flag.load(Ordering::SeqCst) {
            break;
        }

        // Use termion's EventReader with timeout
        if let Ok(event) = termion::event::read_with_timeout(&mut stdin, Duration::from_millis(100)) {
            match event {
                Some(termion::event::Event::Key(key)) => {
                    let char_code = key.to_string().chars().next().unwrap_or('?');
                    if char_code == 'q' {
                        // Send shutdown message and break
                        let _ = try_send(sender, Message::Key('q'));
                        break;
                    } else {
                        let _ = try_send(sender, Message::Key(char_code));
                    }
                }
                _ => {}
            }
        }
    }

    // Restore terminal
    let _ = stdout.show_cursor();
    let _ = stdout.flush();
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting event loop. Press 'q' or Ctrl+C to exit.");

    let (sender, receiver): (Sender<Message>, Receiver<Message>) = crossbeam_channel::unbounded();
    let state = SharedState::new(sender.clone());

    // Spawn signal handler thread
    let state_clone = state.clone();
    let signal_handle = thread::spawn(move || yield_signals(&state_clone));

    // Spawn keyboard listener thread
    let state_clone = state.clone();
    let keyboard_handle = thread::spawn(move || yield_keys(&state_clone));

    // Main event loop
    loop {
        match receiver.recv_timeout(Duration::from_millis(100)) {
            Ok(Message::Key(c)) => println!("Received key: {}", c),
            Ok(Message::Signal(sig)) => {
                println!("Received signal: {:?} - shutting down", sig);
                state.shutdown_flag.store(true, Ordering::SeqCst);
                // Signal other threads
                let _ = sender.send(Message::Shutdown);
                break;
            }
            Ok(Message::Shutdown) => {
                println!("Shutdown received - exiting");
                state.shutdown_flag.store(true, Ordering::SeqCst);
                break;
            }
            Err(_) => {
                // Channel closed or timeout - check if we should exit
                if state.shutdown_flag.load(Ordering::SeqCst) {
                    break;
                }
            }
        }
    }

    // Wait for threads to finish
    let _ = signal_handle.join();
    let _ = keyboard_handle.join();

    println!("All threads stopped. Exiting program.");

    Ok(())
}"
}
