// without closing the connection. The key is to:
// 1. Store the Client in Arc<Mutex<Option<_>>> to share across async contexts
// 2. Keep the Connection task alive by spawning it once and letting it run
// 3. Clone the Client when needed (tokio_postgres::Client is Clone)

use std::sync::Arc;
use tokio::sync::Mutex;
use tokio_postgres::{Client, NoTls};

#[derive(Debug, Clone)]
pub struct DbConfig {
    pub host: String,
    pub port: u16,
    pub user: String,
    pub password: String,
}

pub struct DbContainer {
    config: DbConfig,
    client: Arc<Mutex<Option<Client>>>,
}

impl DbContainer {
    pub fn new(config: DbConfig) -> Self {
        Self {
            config,
            client: Arc::new(Mutex::new(None)),
        }
    }

    /// Ensure we have an active connection. Creates one if needed.
    pub async fn ensure_connected(&self) -> Result<(), tokio_postgres::Error> {
        let mut locked = self.client.lock().await;

        // If no client exists yet, create one
        if locked.is_none() {
            let conn_str = format!(
                "host={} port={} user={} password={}",
                self.config.host,
                self.config.port,
                self.config.user,
                self.config.password
            );

            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

            // CRITICAL: Spawn the connection task and let it run forever
            // This keeps the connection alive as long as the program runs
            tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("Connection closed with error: {}", e);
                }
            });

            *locked = Some(client);
        }

        Ok(())
    }

    /// Get a clone of the cached client
    pub async fn get_client(&self) -> Result<Client, tokio_postgres::Error> {
        self.ensure_connected().await?;

        let guard = self.client.lock().await;
        match &*guard {
            Some(client) => Ok(client.clone()),
            None => Err(tokio_postgres::Error::Closed),
        }
    }

    /// Convenience method to execute a query using the cached connection
    pub async fn execute(&self, query: &str, params: &[&dyn tokio_postgres::types::ToSql]) -> Result<u64, tokio_postgres::Error> {
        let client = self.get_client().await?;
        client.execute(query, params).await
    }
}

