    let result2 = container.execute("SELECT NOW()", &[]).await?;
    println!("✓ Query returned: {} rows\n", result2);

    // Test 3: Use cloned client directly
    println!("Test 3: Using cloned client directly");
    let client = container.get_client().await?;
    let result3 = client.execute("SELECT COUNT(*) FROM pg_database", &[]).await?;
    println!("✓ Query returned: {} rows\n", result3);

