// with critical_section on platforms supporting it.
// Note: Ordering::Relaxed is correct inside critical_section::with()
// because the critical section disables interrupts/prevents preemption,
// providing mutual exclusion equivalent to a mutex lock.

use critical_section;

#[cfg_attr(not(target_arch = "thumbv6m"), allow(unused_imports))]
use core::sync::atomic::{AtomicUsize, Ordering};

struct Channel {
    channel_index: AtomicUsize,
}

impl Channel {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    // Original approach using fetch_add (available on most targets)
    fn fetch_add_original(&self) -> usize {
        self.channel_index.fetch_add(1, Ordering::AcqRel)
    }

    // Replacement using critical_section
    // Ordering::Relaxed is correct here because:
    // 1. critical_section::with() disables interrupts/prevents preemption
    // 2. No concurrent modification possible during the critical section
    // 3. The mutual exclusion from critical_section provides ordering guarantees
    fn fetch_add_with_critical_section(&self) -> usize {
        critical_section::with(|_| {
            let old_val = self.channel_index.load(Ordering::Relaxed);
            self.channel_index.store(old_val + 1, Ordering::Relaxed);
            old_val
        })
    }
}

fn main() {
