    let results2: Vec<usize> = (0..5)
        .map(|_| channel2.fetch_add_original())
        .collect();

    println!("Original fetch_add Results: {:?}", results2);
    assert_eq!(results2, vec![0, 1, 2, 3, 4]);

    println!("\nBoth approaches produce identical results!");
    println!("Using Ordering::Relaxed inside critical_section is CORRECT because:");
    println!("- critical_section provides mutual exclusion");
    println!("- No concurrent access possible during the section");
    println!("- Load/Store pairs within critical section are atomic w.r.t. each other");
