impl TaskData {
    fn new(source: &str) -> Result<Self, Box<dyn std::error::Error>> {
        let bytes = source.as_bytes();

        // Find field positions by parsing the JSON structure manually for demonstration
        // In production, you'd use proper JSON pointer logic
        let data_start = source.find("\"data\"")
            .and_then(|start| start + 7..source.len()).into_iter()
            .next()
            .map(|range| range.start)
            .unwrap_or(0);

