                continue;
            }
            match c as char {
                '\\' => escape = true,
                '"' => {
                    if in_string {
                        data_end = i;
                        break;
                    }
                    in_string = true;
                }
                '{', '[' => depth += 1,
                '}', ']' => depth -= 1,
                _ => {}
            }
        }

        let data_len = data_end.max(data_start);

        // Similar logic for more_data (simplified)
        let more_data_start = source.find("\"more_data\"")
            .and_then(|start| start + 12..source.len()).into_iter()
            .next()
