        let mut md_in_string = false;
        let mut md_escape = false;

        for (i, &c) in bytes[more_data_start..].iter().enumerate() {
            if md_escape {
                md_escape = false;
                continue;
            }
            match c as char {
                '\\' => md_escape = true,
                '"' => {
                    if md_in_string {
                        more_data_end = i;
                        break;
                    }
                    md_in_string = true;
                }
