            let face_center = xf.translation() + hit_normal * 0.5;

            // THE KEY SOLUTION: Create a transform that:
            // 1. Positions at face center
            // 2. Rotates so Z aligns with the hit normal
            // 3. Preserves the block's local rotation orientation

            // Get the block's rotation
            let block_rotation = xf.rotation();

            // Convert world-space normal to block's local space to determine which local face
            let local_normal = block_rotation.mul_vec3(-hit_normal.normalize());

            // Find which local axis the normal is closest to
            let best_axis = [Vec3::X, Vec3::Y, Vec3::Z]
                .iter()
                .max_by_key(|axis| (**axis).dot(local_normal.abs()).abs())
                .unwrap();

            // Determine the sign (+1 or -1) of the axis
            let sign = if (*best_axis).dot(local_normal) < 0.0 { -1.0 } else { 1.0 };

            // Create a quaternion that rotates from the chosen local axis to the world normal
            // This preserves the block's orientation while aligning with the hit face
            let target_normal = hit_normal.normalize();
            let local_axis_aligned = block_rotation.mul_vec3(best_axis * sign);

            // Create rotation that maps our aligned local axis to the hit normal
            let rotation = if local_axis_aligned.dot(target_normal).abs() > 0.999 {
                block_rotation  // Already aligned
            } else {
                // Rotate around the cross product to align
                let up = block_rotation.mul_vec3(Vec3::Y); // Use block's Y as reference up
                let cross = local_axis_aligned.cross(up);
                if cross.length_squared() > 0.0001 {
                    Quat::from_rotation_arc(local_axis_aligned, target_normal) * block_rotation
                } else {
                    block_rotation
                }
            };

            // Draw the gizmo
            gizmos.rect(
                Transform::from_translation(face_center + hit_normal * 0.01)
                    .with_rotation(rotation)
                    .to_isometry(),
                RectConfig {
                    size: Vec2::new(0.9, 0.9),
