        match self {
            GenericVecMut::String(v) => v.remove(index),
            GenericVecMut::I32(v) => v.remove(index),
            GenericVecMut::F32(v) => v.remove(index),
            GenericVecMut::Bool(v) => v.remove(index),
        }
    }

    fn get_element_mut(&mut self, index: usize) -> Option<&mut dyn PropertyValue + 'static> {
        match self {
            GenericVecMut::String(v) => v.get_mut(index).map(|x| x as &mut dyn PropertyValue),
            GenericVecMut::I32(v) => v.get_mut(index).map(|x| x as &mut dyn PropertyValue),
            GenericVecMut::F32(v) => v.get_mut(index).map(|x| x as &mut dyn PropertyValue),
            GenericVecMut::Bool(v) => v.get_mut(index).map(|x| x as &mut dyn PropertyValue),
        }
    }
}

enum GenericOptionMut<'a> {
    String(&'a mut Option<String>),
    I32(&'a mut Option<i32>),
    F32(&'a mut Option<f32>),
    Bool(&'a mut Option<bool>),
}

impl<'a> GenericOptionMut<'a> {
    fn is_none(&self) -> bool {
        match self {
            GenericOptionMut::String(v) => v.is_none(),
            GenericOptionMut::I32(v) => v.is_none(),
            GenericOptionMut::F32(v) => v.is_none(),
            GenericOptionMut::Bool(v) => v.is_none(),
        }
    }

    fn set_to_none(&mut self) {
        match self {
            GenericOptionMut::String(v) => *v = None,
            GenericOptionMut::I32(v) => *v = None,
            GenericOptionMut::F32(v) => *v = None,
            GenericOptionMut::Bool(v) => *v = None,
        }
    }

    fn set_to_default(&mut self) {
        match self {
            GenericOptionMut::String(v) => *v = Some(String::default()),
            GenericOptionMut::I32(v) => *v = Some(i32::default()),
            GenericOptionMut::F32(v) => *v = Some(f32::default()),
            GenericOptionMut::Bool(v) => *v = Some(bool::default()),
        }
    }

    fn get_inner_mut(&mut self) -> Option<&mut dyn PropertyValue> {
        match self {
            GenericOptionMut::String(v) => v.as_mut().map(|x| x as &mut dyn PropertyValue),
            GenericOptionMut::I32(v) => v.as_mut().map(|x| x as &mut dyn PropertyValue),
            GenericOptionMut::F32(v) => v.as_mut().map(|x| x as &mut dyn PropertyValue),
            GenericOptionMut::Bool(v) => v.as_mut().map(|x| x as &mut dyn PropertyValue),
        }
    }
}

/// Simulated UI renderer (since we can't include egui in a self-contained example)
struct SimulatedUi {
    output: Vec<String>,
}

impl SimulatedUi {
    fn new() -> Self {
        SimulatedUi { output: Vec::new() }
    }

    fn label(&mut self, text: &str) {
        self.output.push(format!({:?}: "{}", text));
    }

    fn button_clicked(&self, _label: &str) -> bool {
        true // simulate click
    }

    fn print_output(&self) {
        println!("\n--- UI Output ---");
        for line in &self.output {
            println!("  {}", line);
        }
        println!("-----------------\n");
    }
}

fn string_property(ui: &mut SimulatedUi, title: &str, value: &mut String) {
    ui.label(&format!("String Property [{}]: {}", title, value));
}

fn i_property(ui: &mut SimulatedUi, title: &str, value: &mut i32) {
    ui.label(&format!("Int Property [{}]: {}", title, value));
}

fn f_property(ui: &mut SimulatedUi, title: &str, value: &mut f32) {
    ui.label(&format!("Float Property [{}]: {}", title, value));
}

fn usize_property(ui: &mut SimulatedUi, title: &str, value: &mut usize) {
    ui.label(&format!("Usize Property [{}]: {}", title, value));
}

fn bool_property(ui: &mut SimulatedUi, title: &str, value: &mut bool) {
    ui.label(&format!("Bool Property [{}]: {}", title, value));
}

fn list_property_generic(ui: &mut SimulatedUi, title: &str, vec_val: &mut GenericVecMut<'_>) {
    ui.label(&format!("List Property [{}] ({} items):", title, vec_val.len()));
    let count = vec_val.len();
    for i in 0..count {
        if let Some(elem) = vec_val.get_element_mut(i) {
            ui.label(&format!("  Item {}: {:?}", i, elem));
        }
    }
}

fn option_property_generic(ui: &mut SimulatedUi, title: &str, opt_val: &mut GenericOptionMut<'_>) {
    if opt_val.is_none() {
        ui.label(&format!("Option Property [{}]: None", title));
    } else if let Some(inner) = opt_val.get_inner_mut() {
        ui.label(&format!("Option Property [{}]: Some({:?})", title, inner));
    }
}

/// Universal property dispatcher avoiding duplication
pub fn downcast_property(
    ui: &mut SimulatedUi,
    title: &str,
    value: &mut TypedValue,
) {
    if let Some(string_v) = value.downcast_mut::<String>() {
        string_property(ui, title, string_v);
    } else if let Some(int_v) = value.downcast_mut::<i32>() {
        i_property(ui, title, int_v);
    } else if let Some(float_v) = value.downcast_mut::<f32>() {
        f_property(ui, title, float_v);
    } else if let Some(usize_v) = value.downcast_mut::<usize>() {
        usize_property(ui, title, usize_v);
    } else if let Some(bool_v) = value.downcast_mut::<bool>() {
        bool_property(ui, title, bool_v);
    } else if let Some(vec_val) = value.try_as_vec_any() {
        // Single handler for ALL Vec<T> variants!
        list_property_generic(ui, title, vec_val);
    } else if let Some(opt_val) = value.try_as_option_any() {
        // Single handler for ALL Option<T> variants!
        option_property_generic(ui, title, opt_val);
    } else {
        ui.label(&format!("Field {}: unknown type", title));
    }
}

