  "main.rs": "// Self-contained example demonstrating how to rehydrate tracing spans across 
// asynchronous boundaries in a multi-stage async application using OpenTelemetry.

use std::sync::Arc;
use tokio::time::Duration;
use tracing::{info, instrument, span, Level, Span};
use opentelemetry::global;
use opentelemetry_sdk::trace::SdkTracerProvider;
use opentelemetry_stdout::SpanExporter;
use tracing_subscriber::{layer::SubscriberExt, Registry};
use tracing_opentelemetry::OpenTelemetryLayer;

/// Shared context representing the request lifecycle state.
/// We store the parent Span here to allow subsequent stages to reattach 
/// to the trace context even if they execute on different threads/tasks.
struct RequestContext {
    /// The root span for this entire request.
    parent_span: Span,
}

#[tokio::main]
async fn main() {
    // 1. Initialize OpenTelemetry Tracer Provider
    let exporter = SpanExporter::default();
    let batch_processor = opentelemetry_sdk::trace::BatchSpanProcessor::builder(
        exporter,
        opentelemetry_sdk::runtime::Tokio,
    )
    .build();
    let provider = SdkTracerProvider::builder()
        .with_span_processor(batch_processor)
        .build();
    let _tracer = global::set_tracer_provider(provider);

    // 2. Initialize Tracing with OpenTelemetry Layer
    // This ensures tracing::Spans map to OpenTelemetry spans.
    let telemetry = OpenTelemetryLayer::builder()
        .with_tracer(global::tracer("pingora-proxy-example"))
        .build();

    let subscriber = Registry::default()
        .with(telemetry)
        .with(tracing_subscriber::fmt::layer().with_target(false));

    tracing::subscriber::set_global_default(subscriber).expect("setting default subscriber failed");

    println!("--- Starting Request Lifecycle Simulation ---");

    // 3. Create the Root Request Span (Parent)
    let root_span = span!(Level::INFO, "Request/Parent Span", request_id = 12345);

    // Wrap the span in an Arc so it can be safely moved and cloned across threads.
    let request_context = RequestContext {
        parent_span: root_span,
    };

    // Clone context to move it into the first task
    let ctx_stage1 = Arc::new(request_context);

    // 4. Simulate Stage 1 (Async Task)
    let handle1 = tokio::spawn(async move {
        run_stage(ctx_stage1, "Stage 1").await;
    });

    // 5. Simulate Stage 2 (Async Task - could be on a different logical path)
    // Note: We don't wait for Stage 1 to start Stage 2 immediately, simulating parallel/delayed stages.
    // In real Pingora, these might be callback handlers triggered by I/O.
    let handle2 = tokio::spawn(async move {
        // Simulate a slight delay to ensure scheduling variance
        tokio::time::sleep(Duration::from_millis(50)).await;
        run_stage(Arc::clone(&ctx_stage1), "Stage 2").await;
    });

    // Wait for completion
    let _ = futures::join!(handle1, handle2);

    println!("--- Request Lifecycle Complete ---");
}

/// Simulates an instrumentation stage (e.g., Upstream, Auth, Routing).
/// Crucially, we retrieve the parent span from the context and re-enter it 
/// to ensure our child span links correctly to the root trace.
#[instrument(name = "{stage_name}", skip(context))]
async fn run_stage(context: Arc<RequestContext>, stage_name: &str) {
    let start_time = std::time::Instant::now();

    // *** SOLUTION CORE ***
    // To rehydrate the parent context in this new task/thread:
    // 1. Access the stored Span from the shared context.
    // 2. Enter the span using .enter(). This pushes it onto the thread-local
    //    active span stack for this duration.

    // Clone the span handle (cheap, just a reference count bump)
    let parent_handle = context.parent_span.clone(); 

    // Re-activate the parent span for this execution context
    let _guard = parent_handle.enter();

    // Now that the parent is active, creating a new span inside this block
    // will automatically attach it as a child of 'context.parent_span'.
    // This solves the 'called back anytime/on any thread' requirement.

    let child_span = span!(Level::DEBUG, "Processing", stage = stage_name);
    let _span_guard = child_span.enter();

    info!("Executing {}", stage_name);

    // Simulate work
    tokio::time::sleep(Duration::from_millis(100)).await;

    info!("Finished {}. Duration: {:?}", stage_name, start_time.elapsed());
}

// Helper to ensure the example compiles with standard imports without needing extra deps for join
mod futures {
    pub use futures_util::future::join;
}
// Add to Cargo.toml dependencies implicitly for simplicity, or use tokio join syntax
// Updating to use tokio::join for cleaner dependency profile" 
