    let height = rows as usize * 12;

    let buffer_size = width * height * 3;

    println!("Creating shared memory buffer: {}x{} @ {} bytes", width, height, buffer_size);

    let mut shm = match ShmBuffer::new(buffer_size) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("Failed to create shared memory: {}", e);
            std::process::exit(1);
        }
    };

