  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, Waker};
use tokio::time::{sleep, Duration};

/// Represents the result of attempting to poll a future synchronously.
enum TryPollResult<X> {
    /// The future completed immediately without yielding.
    Ready(X),
    /// The future yielded and needs to be driven by the runtime.
    Pending,
}

/// Attempts to poll the future once with a No-op Waker.
/// 
/// # Warning
/// 
/// This operation is generally unsafe for production code as it bypasses
/// the normal executor machinery. It assumes the future does not depend on
/// specific Waker implementations for state storage during a Pending state,
/// which is true for most standard futures but not guaranteed by the trait.
fn try_poll<F, X>(future: Pin<&mut F>) -> TryPollResult<X>
where
    F: Future<Output = X>,
{
    // Create a waker that does nothing. This is sufficient because:
    // 1. If Ready: We don't need to wake the future anymore.
    // 2. If Pending: We intend to spawn the future onto the real runtime,
    //    which will provide the correct Waker on the next poll.
    let waker = Waker::noop();
    let mut context = Context::from_waker(&waker);

    // Perform the single poll step
    match future.as_mut().poll(&mut context) {
        Poll::Ready(result) => TryPollResult::Ready(result),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    println!("Testing manual polling with Tokio...");

    // --- Case 1: Future is immediately Ready ---
    println!("\n[Case 1] Checking an immediately ready future:");
    let mut ready_future = Box::pin(async {
        println!("  -> Executing ready future payload...");
        42
    });

    // We need to pin the box to pass to try_poll
    let result = try_poll(Box::pin(&mut ready_future));

    match result {
        TryPollResult::Ready(value) => {
            println!("  -> Future was READY. Value: {}", value);
        }
        TryPollResult::Pending => {
            println!("  -> Future was PENDING (Unexpected for this test)");
        }
    }

    // --- Case 2: Future is Pending (needs runtime) ---
    println!("\n[Case 2] Checking a deferred future (Tokio Sleep):");
    let mut pending_future = Box::pin(sleep(Duration::from_millis(100)));

    // Note: Box::pin returns a Pin<Box<T>>. We need Pin<&mut F>.
    // Box implements Unpin, so Box::get_mut() gives &mut T.
    // Then Pin::new creates Pin<&mut T>.
    // However, sleep returns a Future. 
    // We can use .as_mut() on the existing Pin.
    let mut p_pending = Box::pin(sleep(Duration::from_millis(100)));

    match try_poll(p_pending.as_mut()) {
        TryPollResult::Ready(_) => {
            println!("  -> Future was READY (Unexpected for this test)");
        }
        TryPollResult::Pending => {
            println!("  -> Future was PENDING. Spawning task...");
            // Since we determined it's pending, we hand ownership to the runtime.
            // We unwrap the Pin to move the future into spawn.
            let _handle = tokio::spawn(async move {
                println!("  -> Task started...");
                sleep(Duration::from_millis(100)).await;
                println!("  -> Task completed!");
            });
            // Give it a moment to finish
            tokio::time::sleep(Duration::from_millis(150)).await;
        }
    }

    println!("\nDone.");
}
