use radiate::tree::node::{NodeType, Vertex, Leaf};
use radiate::types::{Real, Int};
use std::f64;
use tokio;

#[derive(Clone, Debug)]
struct SqrtPlusOne;

impl Operation<1> for SqrtPlusOne {
    fn eval(&self, inputs: &[Real]) -> Real {
        let x = inputs[0];
        // Avoid negative numbers for sqrt
        if x < 0.0 {
            0.0
        } else {
            (x.sqrt()) + 1.0
        }
    }

    fn name(&self) -> &'static str {
        "sqrt_plus_one"
    }
}

#[derive(Clone, Debug)]
struct MaxZero;

impl Operation<1> for MaxZero {
    fn eval(&self, inputs: &[Real]) -> Real {
        *inputs[0].max(&0.0)
    }

    fn name(&self) -> &'static str {
        "max_zero"
    }
}

async fn run_gp() {
    use radiate::tree::op_store::OpStore;
    use radiate::problem::Problem;
    use radiate::algorithm::gpgp::GPGP;
    use radiate::types::RealData;

    // Define problem data (simple regression example)
    let x_data: Vec<f64> = (0..=10).map(|x| x as f64).collect();
    let y_data: Vec<f64> = x_data.iter().map(|&x| x * x + x).collect();

    let problem: Box<dyn Problem<Real>> = Box::new(RegressionProblem {
        x: x_data,
        y: y_data,
    });

    // Build operator store with both built-in and custom operators
    let mut op_store = OpStore::default();

    op_store.add_op(NodeType::Vertex, vec![
        Box::new(radiate::tree::Op::add()) as Box<dyn Operation<Real, 2>>,
        Box::new(radiate::tree::Op::mul()),
        Box::new(radiate::tree::Op::sub()),
        Box::new(SqrtPlusOne) as Box<dyn Operation<Real, 1>>,
        Box::new(MaxZero),
    ]);

    op_store.add_op(NodeType::Leaf, vec![
        Box::new(radiate::tree::Op::var(0)) as Box<dyn Operation<Real, 0>>,
    ]);

    // Configure GP algorithm
    let alg = GPGP::<Real>::default()
        .with_pop_size(50)
        .with_generations(30)
        .with_elitism_ratio(0.1)
        .with_crossover_rate(0.9)
        .with_mutation_rate(0.05)
        .with_max_depth(6);

    let result = alg.optimize(problem, &op_store).await.unwrap();

    println!("Best fitness achieved: {}", result.fitness);
    if let Some(best_tree) = result.best_node {
        println!("Best expression found: {:?}", best_tree);
    }
}

// Simple regression problem wrapper
struct RegressionProblem {
    x: Vec<f64>,
    y: Vec<f64>,
}

impl Problem<Real> for RegressionProblem {
    fn fitness(&self, node: &dyn Node<Real>) -> Real {
        let mut error: f64 = 0.0;
        let n = self.x.len();

        for i in 0..n {
            let input = vec![self.x[i] as Real];
            let predicted = node.eval(&input);
            let target = self.y[i] as Real;
            let diff = predicted - target;
            error += diff * diff; // MSE
        }

        // Lower is better for MSE
        -(error / n as Real)
    }

    fn num_inputs(&self) -> usize {
        1 // We're using just variable 0
    }
}

#[tokio::main]
async fn main() {
    run_gp().await;
}
