use serde::de::{self, Visitor, MapAccess, SeqAccess};
use std::fmt;

/// Simple enum B with two variants
#[derive(Debug, Clone, PartialEq)]
enum B {
    Simple,
    Named(String),
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        // Custom deserialization for B
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                f.write_str("string or map")
            }

            fn visit_str<E>(self, v: &str) -> Result<B, E>
            where
                E: de::Error,
            {
                if v == "Simple" {
                    Ok(B::Simple)
                } else {
                    Err(de::Error::unknown_variant(v, &["Simple"]))
                }
            }

            fn visit_map<M>(self, mut map: M) -> Result<B, M::Error>
            where
                M: MapAccess<'de>,
            {
                let key: Option<String> = map.next_key()?;
                let val: String = map.next_value()?;
                match key {
                    Some(k) if k == "named" => Ok(B::Named(val)),
                    _ => Err(de::Error::invalid_type(
                        de::Unexpected::Map,
                        &"expected key \"named\"",
                    )),
                }
            }
        }

        deserializer.deserialize_any(BVisitor)
    }
}

/// Struct A with nested Vec<B>
#[derive(Debug, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

/// Custom visitor for A
struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("struct A")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut x = None;
        let mut b = None;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "x" => x = Some(map.next_value()?),
                "b" => b = Some(map.next_value()?),
                _ => {
                    // ignore unknown fields
                    map.next_value::<de::IgnoredAny>()?;
                }
            }
        }

        Ok(A {
            x: x.ok_or_else(|| de::Error::missing_field("x"))?,
            b: b.unwrap_or_default(),
        })
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

