edition = "2021"

[dependencies]",
  "main.rs": "//! Shell command tokenizer that splits input into tokens respecting single quotes.
//!
//! Similar to how bash handles single-quoted strings:
//! - Text inside single quotes is treated as a literal (spaces preserved)
//! - Multiple consecutive spaces outside quotes are collapsed
//! - Quotes themselves are not included in the output

fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_quotes = false;

    for ch in input.chars() {
        match ch {
            '\'' => {
                in_quotes = !in_quotes;
            }
            _ if in_quotes => {
                // Inside quotes: preserve everything including spaces
                current.push(ch);
            }
            c if c.is_whitespace() => {
                // Whitespace outside quotes: ends current token if any
                if !current.is_empty() {
                    tokens.push(current.clone());
                    current.clear();
                }
            }
            c => {
                // Non-whitespace outside quotes: append to current token
                current.push(c);
            }
        }
    }

    // Push any remaining token
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    // Test case from the problem statement
    let input = " one  ' two  'three    four";
    let result = tokenize(input);

    println!("Input: {:?}", input);
    println!("{} args:", result.len());
    for token in &result {
        println!("<{}>", token);
    }

    // Additional test cases
    println!("\n--- Additional tests ---");

    let test_cases = vec![
        ("a b c", 3),
        ("'hello world'", 1),
        ("a'b'c", 1),
        ("''", 0),
        ("x 'y z' w", 3),
        ("  leading  spaces  ", 1),
    ];

    for (input, expected_count) in test_cases {
        let result = tokenize(input);
        let status = if result.len() == expected_count { "✓" } else { "✗" };
        println!("{} {:?} -> {} tokens", status, input, result.len());
    }
}"

