    "main.rs": "use std::convert::Infallible;
use std::net::SocketAddr;
use std::sync::Arc;
use axum::{
    body::Body,
    extract::ws::{Message, WebSocket},
    response::IntoResponse,
    routing::get,
    Router,
};
use http::{header, Request, Response, StatusCode};
use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use tower::{Layer, Service};

// Configuration
const ALLOWED_ORIGINS: [&str; 2] = ["https://www.example.com", "http://localhost:3000"];

// Custom Layer to check Origin header before any handler runs
#[derive(Clone)]
struct OriginFilter {
    _phantom: std::marker::PhantomData<()>,
}

impl OriginFilter {
    fn new() -> Self {
        Self {
            _phantom: std::marker::PhantomData,
        }
    }
}

impl<S> Layer<S> for OriginFilter {
    type Service = OriginService<S>;

    fn layer(&self, inner: S) -> Self::Service {
        OriginService { inner }
    }
}

struct OriginService<S> {
    inner: S,
}

impl<S, B> Service<Request<B>> for OriginService<S>
where
    S: Service<Request<B>, Response = Response<Body>, Error = Infallible>,
    S: Send + 'static,
    B: Send + 'static,
{
    type Response = Response<Body>;
    type Error = Infallible;
    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>;

    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        self.inner.poll_ready(cx)
    }

    fn call(&mut self, req: Request<B>) -> Self::Future {
        let origin_header = req.headers().get(header::ORIGIN);
        let origin_ok = match origin_header {
            Some(value) => {
                match value.to_str() {
                    Ok(o) => ALLOWED_ORIGINS.iter().any(|&a| o == a),
                    Err(_) => false,
                }
            }
            None => false,
        };

        if !origin_ok {
            tracing::warn!("Forbidden Origin: {:?}", origin_header.map(|h| h.to_str().unwrap_or("???"))); 
            let res = Response::builder()
                .status(StatusCode::FORBIDDEN)
                .body(Body::from("Access Denied: Invalid Origin"))
                .expect("Failed to build error response");
            return Box::pin(async move { Ok(res) });
        }

        tracing::info!("Origin allowed: {:?}", origin_header.map(|h| h.to_str().unwrap_or("???")));
        let mut svc = self.inner.take();
        let fut = svc.call(req);
        self.inner = svc;
        Box::pin(fut)
    }
}

async fn ws_handler(
    ws: WebSocketUpgrade,
) -> impl IntoResponse {
    ws.on_upgrade(handle_socket).await
}

async fn handle_socket(mut socket: WebSocket) {
    while let Some(msg) = socket.recv().await {
        match msg {
            Message::Text(text) => {
                let resp = format!("Server received: {}", text);
                socket.send(Message::Text(resp)).await.unwrap();
            }
            Message::Close(_) => {
                socket.close().await.unwrap();
                break;
            }
            _ => {}
        }
    }
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();

    let app = Router::new()
        .route("/ws", get(ws_handler))
        .layer(OriginFilter::new());

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("Listening on {}:3000. Test by opening ws://localhost:3000/ws in your browser console.", addr.ip());
    println!("Note: Requests without 'Origin' header or from blocked domains will receive 403.");

    let listener = TcpListener::bind(addr).await.expect("Failed to bind");
    axum::serve(listener, app).await.expect("Server failed");
}",
