/// Manually polls a future once.
/// Returns Ready if completed, Pending otherwise.
/// WARNING: Uses a noop waker - if future completes later, we won't know.
fn try_poll_once<F, T>(future: &mut F) -> TryPollResult<T>
where
    F: Future<Output = T>,
{
    // Create a dummy Context with a no-op Waker
    let waker = futures::task::noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

async fn fast_future() -> String {
    "already done".to_string()
}

async fn slow_future() -> String {
    sleep(Duration::from_millis(100)).await;
    "completed after delay".to_string()
}

