    println!("=== Manual Future Polling Demo ===\n");

    // Example 1: Fast future (should be ready immediately)
    let mut fast = fast_future();
    match try_poll_once(&mut fast) {
        TryPollResult::Ready(value) => {
            println!("✓ Fast future was READY");
            println!("  Value: {}\n", value);
        }
        TryPollResult::Pending => {
            println!("✗ Fast future was PENDING (unexpected)\n");
        }
    }

    // Example 2: Slow future (should NOT be ready initially)
    let mut slow = slow_future();
    match try_poll_once(&mut slow) {
        TryPollResult::Ready(value) => {
            println!("✗ Slow future was READY (unexpected)");
            println!("  Value: {}\n", value);
        }
        TryPollResult::Pending => {
            println!("✓ Slow future was PENDING as expected");
            println!("  Spawning task to complete it...\n");

            // Spawn a task to wait for completion
            tokio::spawn(async move {
                match slow.await {
                    "completed after delay" => {
                        println!("  ✓ Task completed: received expected value");
                    }
                    other => {
                        println!("  ? Task completed with unexpected: {}", other);
                    }
                }
            });
        }
    }

    // Wait a bit for spawned task to complete
    sleep(Duration::from_millis(150)).await;

    println!();
    println!("=== Important Notes ===");
    println!("1. Using noop_waker() means we won't be notified if future completes later");
    println!("2. This pattern is unusual - prefer normal .await when possible");
    println!("3. The future must live at least as long as the manual poll");
    println!("4. Only safe when you handle both Ready and Pending appropriately");
}"
}
