    let (shutdown_tx, shutdown_rx) = broadcast::channel::<()>(1);

    // Spawn queue handler with shutdown receiver
    let queue_handler = QueueHandler::new(shutdown_rx);
    let queue_task = tokio::spawn(async move {
        queue_handler.run().await;
        info!("Queue handler stopped gracefully");
    });

    // Build Actix Web server with shutdown handle
    let server = HttpServer::new(|| {
