    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            warn!("Received Ctrl+C, initiating graceful shutdown...");
        }
        _ = queue_task => {
            warn!("Queue handler task ended unexpectedly");
        }
    }

    // Signal shutdown to queue handler
    let _ = shutdown_tx.send(());

    // Stop the Actix server gracefully
    server.stop(true).await;

    // Wait for queue handler to finish
    let _ = queue_task.await;

