/// Parse an ISO date string from LanceDB into a DateTime<Utc>
/// Handles both with and without fractional seconds
pub fn parse_lancedb_date(date_str: &str) -> Result<DateTime<Utc>, Box<dyn Error>> {
    // Try multiple formats since some dates have fractional seconds and some don't
    let formats = [
        "%Y-%m-%dT%H:%M:%S",           // No fractional seconds (e.g., "1970-01-01T00:00:00")
        "%Y-%m-%dT%H:%M:%S%.f",        // With fractional seconds (e.g., "2025-08-02T17:35:41.409")
        "%Y-%m-%dT%H:%M:%SZ",          // UTC without fractional
        "%Y-%m-%dT%H:%M:%S%.fZ",       // UTC with fractional
        "%Y-%m-%dT%H:%M:%S%.f%:z",     // With timezone offset
    ];

    for format in formats.iter() {
        if let Ok(dt) = DateTime::parse_from_str(date_str, format) {
            return Ok(dt.with_timezone(&Utc));
        }
    }

    Err(format!("Failed to parse date: {}", date_str).into())
