// Define a custom Stream that wraps tokio::fs::File to yield Bytes.
pin_project! {
    pub struct FileDataStream {
        file: Option<File>,
        buf: Vec<u8>,
        #[pin]
        waker: Option<std::task::Waker>,
    }
