impl Stream for FileDataStream {
    type Item = Result<http_body_util::Frame<Bytes>, io::Error>;

    fn poll_next(
        self: std::pin::Pin<&mut Self>,
        cx: &mut std::task::Context<'_>,
    ) -> std::task::Poll<Option<Self::Item>> {
        let mut this = self.project();

        if let Some(file) = this.file.as_mut() {
            match file.try_read(&mut this.buf[..]) {
                Ok(n) => {
                    if n > 0 {
                        let data = Bytes::copy_from_slice(&this.buf[..n]);
                        return std::task::Poll::Ready(Some(Ok(http_body_util::Frame::data(data))));
                    } else {
                        // EOF
                        *this.file = None;
                        std::task::Poll::Ready(None)
                    }
