use std::fmt::{Debug, Display};

// Not my real error, simplified for the example
#[derive(Debug, thiserror::Error)]
pub enum FrameworkError {
    #[error("400: {0}")]
    Error400(String),

    #[error("Internal error")]
    Internal(String),
}

/// Extension trait for logging with preserved caller location
pub trait LogChangeErrForRespExt {
    type R;

    /// Logs error and returns internal server error without details
    fn log_hide_err(self) -> Self::R;

    /// Logs client error and returns bad request with error details
    fn log_and_explain_400(self) -> Self::R;
}

impl<T, E: Debug + Display + 'static> LogChangeErrForRespExt for Result<T, E> {
    type R = Result<T, FrameworkError>;

    /// Logs the error using [log::warn] and replaces the error with
    /// an internal server error without exposing private details.
    #[track_caller]
    fn log_hide_err(self) -> Self::R {
        match self {
            Ok(ok) => Ok(ok),
            Err(err) => {
                let loc = std::panic::Location::caller();
                // Format: [FILE:LINE] shows where the .method() was called
                log::warn!(
                    "HIDING ERROR @ {}:{} | Module: {} | Error: {}",
                    loc.file(),
                    loc.line(),
                    std::any::type_name_of_val(&loc),
                    err
                );
                Err(FrameworkError::Internal("Unexpected error occurred".to_string()))
            }
        }
    }

    /// Logs the client error and returns the Display string of the original error
    #[track_caller]
    fn log_and_explain_400(self) -> Self::R {
        match self {
            Ok(ok) => Ok(ok),
