// A custom predicate that holds the current log level in shared memory.
// Changing the content of this Mutex instantly affects all layers
// referencing it.
struct DynamicLevelFilter {
    level: Arc<Mutex<Level>>,
}

impl Filter for DynamicLevelFilter {
    fn enabled(&self, metadata: &tracing::Metadata<'_>) -> bool {
        match self.level.lock() {
            Ok(guard) => *metadata.level() <= *guard,
            Err(_) => false,
        }
    }
}

