    error::ReadlineError,
    hint::Hinter,
    history::DefaultHistory,
    highlight::Highlighter,
    validate::Validator,
    Cmd, Editor, EventHandler, KeyEvent, Modifiers, Movement, RepeatCount, Event,
};
use std::io;
use rustyline::conditional_event_handler::ConditionalEventHandler;

// Custom event handler that removes trailing whitespace and inserts a character
struct MyEventHandler {
    insert: String,
}

impl MyEventHandler {
    fn new(insert: char) -> MyEventHandler {
        let insert = String::from(insert);
        MyEventHandler { insert }
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Get the substring before the cursor
        let before_cursor = &line[..pos];

        // Find the last non-whitespace character before the cursor
        if let Some(last_char_pos) = before_cursor.chars().rposition(|c| !c.is_whitespace()) {
            // Check if there's whitespace between the last char and cursor
            let distance = pos - (last_char_pos + 1);
            if distance > 0 {
                // Delete all whitespace after the last non-whitespace character
                // and insert our character
                // Note: Cmd::Replace will place cursor at START of replacement
                // To get cursor AFTER, we use Insert which handles positioning correctly
                let movement = Movement::BackwardChar(distance as RepeatCount);
                Some(Cmd::Replace(movement, Some(self.insert.clone())))
            } else {
                // No whitespace to delete, just insert normally
                Some(Cmd::Insert(self.insert.clone()))
            }
        } else {
            // No non-whitespace characters found, just insert
            Some(Cmd::Insert(self.insert.clone()))
        }
    }
}

fn bind_handler(editor: &mut Editor<MyHelper, DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, Modifiers::NONE);
    let handler = MyEventHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(event, handler);
}

#[derive(Default)]
struct MyHelper;

impl Helper for MyHelper {}
impl Hinter for MyHelper {
    type Hint = ();
}
impl Highlighter for MyHelper {}
impl Validator for MyHelper {}

fn main() -> Result<(), ReadlineError> {
    let mut rl = Editor::<MyHelper, DefaultHistory>::new()?;
    rl.load_history("history.txt")?;

    // Bind handlers for '.' and ','
    bind_handler(&mut rl, '.');
    bind_handler(&mut rl, ',');

    println!("SQL CLI Demo - Type SQL and press Enter.");
    println!("Try: 'SELECT bo<TAB>' then type '.' or ','");
    println!("Cursor should be positioned after the dot/comma for easy column entry.");
    println!();

    loop {
        let readline = rl.readline("zql> ");
        match readline {
            Ok(line) => {
                rl.add_history_entry(line.as_str());
                println!("You entered: {}", line);

                if line.trim().to_uppercase() == "EXIT" || line.trim().to_uppercase() == "QUIT" {
                    break;
                }
            }
            Err(ReadlineError::Interrupted) => {
                println!("Interrupted by Ctrl+C");
                continue;
            }
            Err(ReadlineError::Eof) => {
                println!("EOF reached. Goodbye!");
                break;
            }
            Err(err) => {
                eprintln!("Error: {:?}", err);
                break;
            }
        }
    }

    rl.save_history("history.txt")?;
    Ok(())
}"
}

