// The key insight: You MUST keep the Connection future alive, not just the Client.
// If the Connection task drops, all Clients created from that connection will fail.

use std::sync::Arc;
use tokio::sync::{Mutex, RwLock};
use tokio_postgres::{NoTls, Client as PostgresClient};

#[derive(Debug)]
pub struct DbConfig {
    pub port: u16,
    pub name: String,
    pub user: String,
    pub password: String,
}

pub struct DbContainer {
    db_config: DbConfig,
    // Cache the client behind Arc + Mutex for thread-safe sharing
    cached_client: Mutex<Option<Arc<PostgresClient>>>,
    // CRITICAL: Keep the Connection alive! This ensures the client stays connected.
    connection_handle: Mutex<Option<tokio::task::JoinHandle<Result<(), tokio_postgres::Error>>>>,
}

impl Drop for DbContainer {
    fn drop(&mut self) {
        // Cancel the background connection task if it exists
        let handle = {
            let mut guard = self.connection_handle.blocking_lock();
            guard.take()
        };
        if let Some(handle) = handle {
            handle.abort();
        }
    }
}

impl DbContainer {
    pub fn new(db_config: DbConfig) -> Self {
        Self {
            db_config,
            cached_client: Mutex::new(None),
            connection_handle: Mutex::new(None),
        }
    }

    async fn connect(&self) -> Result<Arc<PostgresClient>, tokio_postgres::Error> {
        let conn_str = format!(
            "host=localhost port={} user={} password={}" 
            .to_string(),
            self.db_config.port,
            self.db_config.user,
            self.db_config.password,
        );

        // Check if we already have a cached client
        let mut client_guard = self.cached_client.lock().await;

        if let Some(ref client) = *client_guard {
            tracing::debug("Using cached database client");
            return Ok(Arc::clone(client));
        }

        tracing::info!("Creating new database connection...");

        // Establish new connection
        let (client, connection) = tokio_postgres::connect(&conn_str, NoTls).await?;

        // CRITICAL: Spawn the connection handler to keep the connection alive!
        let join_handle = tokio::spawn(async move {
            tracing::info!("Connection handler started");
            match connection.await {
                Ok(()) => {
                    tracing::warn!("Connection closed normally");
                    Ok(())
                }
                Err(e) => {
                    tracing::error!("Connection error: {}", e);
                    Err(e)
                }
            }
        });

        // Store the connection handle so it doesn't drop when this function returns
        *self.connection_handle.lock().await = Some(join_handle);

        // Clone the client into Arc and cache it
        let client_arc = Arc::new(client);
        *client_guard = Some(Arc::clone(&client_arc));

        Ok(client_arc)
    }

