use std::time::Duration;

#[derive(Debug)]
enum Message {
    Signal(i32),
    KeyPress(char),
    Shutdown,
}

fn yield_signals(sender: mpsc::Sender<Message>, running: Arc<AtomicBool>) {
    if let Ok(mut signals) = Signals::new(&[SIGINT, SIGTERM]) {
        let mut sig_iter = signals.forever();
        // Use select! pattern with timeout to allow checking shutdown flag
        loop {
            if !running.load(Ordering::Relaxed) {
                break;
            }
            match sig_iter.recv_timeout(Duration::from_millis(100)) {
                Ok(Some(sig)) => {
                    let _ = sender.send(Message::Signal(sig));
                }
                _ => {}
            }
        }
    }
}

fn yield_keys(sender: mpsc::Sender<Message>, running: Arc<AtomicBool>) -> io::Result<()> {
    let mut stdout: RawTerminal<Stdout> = io::stdout().into_raw_mode()?;
    let stdin = io::stdin().lock();

    for event in stdin.events() {
        if !running.load(Ordering::Relaxed) {
            // Restore raw mode before exiting
            drop(stdout);
            return Ok(());
        }

        if let Ok(Event::Key(Char(key))) = event {
            if key == 'q' || key == 'Q' {
                let _ = sender.send(Message::Shutdown);
                drop(stdout);
                return Ok(());
            } else if key != '\x7F' && key != '\r' { // Ignore backspace and enter
                let _ = sender.send(Message::KeyPress(key));
            }
        }

        // Small sleep to avoid busy-waiting
        thread::sleep(Duration::from_millis(50));
    }

    drop(stdout);
    Ok(())
}

fn main() -> io::Result<()> {
    println!("Starting event loop. Press 'q' to quit.");
    println!("Signals SIGINT/SIGTERM will also trigger messages.");

    let (sender, receiver) = mpsc::channel::<Message>();
    let running = Arc::new(AtomicBool::new(true));

    // Clone for threads
    let sender_signals = sender.clone();
    let running_signals = running.clone();
    let thread_signals = thread::spawn(move || {
        yield_signals(sender_signals, running_signals);
    });

    let sender_keys = sender.clone();
    let running_keys = running.clone();
    let thread_keys = thread::spawn(move || {
        if let Err(e) = yield_keys(sender_keys, running_keys) {
            eprintln!("Key reader error: {}", e);
        }
    });

    let should_shutdown = Arc::new(AtomicBool::new(false));
    let should_shutdown_main = should_shutdown.clone();

    // Handle received messages
    for msg in receiver.iter() {
        if should_shutdown_main.load(Ordering::Relaxed) {
            break;
        }

        match msg {
            Message::Signal(sig) => {
                println!("Received signal: {}", sig);
                if sig == SIGINT || sig == SIGTERM {
                    println!("Shutting down due to signal...");
                    should_shutdown.store(true, Ordering::Relaxed);
                    break;
                }
            }
            Message::KeyPress(key) => {
                println!("Key pressed: {}", key);
            }
            Message::Shutdown => {
                println!("Shutdown requested by user...");
                should_shutdown.store(true, Ordering::Relaxed);
                break;
            }
        }
    }

    // Signal all threads to stop
    running.store(false, Ordering::Relaxed);

    // Join threads with timeout
    println!("Waiting for threads to terminate...");
    if let Ok(handle) = thread_signals.join() {
        drop(handle);
    }
    if let Ok(handle) = thread_keys.join() {
        drop(handle);
    }

    println!("All threads terminated. Program exiting.");
    Ok(())
}"
