use tokio::sync::{mpsc, broadcast};
use tokio_stream::{wrappers::BroadcastStream, StreamExt};

// Event type to send over broadcast channel
#[derive(Debug, Clone)]
pub enum Event {
    Data(String),
    Shutdown,
}

// Wrapper around the broadcaster with shutdown control
pub struct EventSender {
    tx: Arc<broadcast::Sender<Event>>,
    shutdown: Arc<AtomicBool>,
}

impl Clone for EventSender {
    fn clone(&self) -> Self {
        EventSender {
            tx: self.tx.clone(),
            shutdown: self.shutdown.clone(),
        }
    }
}

impl EventSender {
    pub fn send(&self, data: String) -> Result<(), broadcast::SendError<Event>> {
        if self.shutdown.load(Ordering::SeqCst) {
            return Err(broadcast::error::SendError(Event::Data(data)));
        }
        self.tx.send(Event::Data(data))
    }

    pub fn trigger_shutdown(&self) {
        self.shutdown.store(true, Ordering::SeqCst);
        // Try to notify listeners of shutdown
        let _ = self.tx.send(Event::Shutdown);
    }
}

// Factory to create new broadcast streams
pub struct EventStreamFactory {
    tx: Arc<broadcast::Sender<Event>>,
    shutdown: Arc<AtomicBool>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl futures_core::stream::Stream<Item = Event> + Send + '_ {
        let mut rx = self.tx.subscribe();
        BroadcastStream::new(rx).filter_map(move |event| {
            if matches!(event, Ok(Event::Shutdown)) || self.shutdown.load(Ordering::SeqCst) {
                None
            } else {
                event.ok()
            }
        })
    }

    pub fn shutdown_sender(&mut self) {
        // Drop the sender to prevent new sends
        self.tx.send_event = || {};
        self.shutdown.store(true, Ordering::SeqCst);
        let _ = self.tx.send(Event::Shutdown);
    }
}

fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel(100);
    let shutdown = Arc::new(AtomicBool::new(false));
    let tx = Arc::new(tx);

