    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>, // neighbor list
}

impl B {
    pub fn new(pos: [f64; 3]) -> Self {
        B {
            r: pos.to_vec(),
            v: vec![0.0; 3],
            f: vec![0.0; 3],
            nb: Vec::new(),
        }
    }

    /// Criterion function - returns squared distance
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];
        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// QUESTION 1: Safe version without unsafe pointers
    /// Uses .get() for safe indexing instead of as_ptr() + unsafe deref
    pub fn build_lists_safe(&mut self) {
        let nelems = self.get_nelems();

        self.elems.iter_mut().enumerate().for_each(|(i, elem_i)| {
            elem_i.nb.clear();

            for j in 0..nelems {
                if i == j {
                    continue;
                }

                // SAFE: use get() instead of unsafe ptr arithmetic
                if let Some(elem_j) = self.elems.get(j) {
                    if elem_i.criterion(elem_j) < self.cutoff {
                        elem_i.nb.push(j);
                    }
                }
            }
        });
    }

    /// QUESTION 2: Modify both elements symmetrically
    /// When criterion is met, add j to i.nb AND i to j.nb
    pub fn build_lists_symmetric(&mut self) {
        let nelems = self.get_nelems();

        // Clear all neighbor lists first
        for elem in &mut self.elems {
            elem.nb.clear();
        }

        // Only check pairs where i < j to avoid duplicate work
        for i in 0..nelems {
            for j in (i + 1)..nelems {
                if let (Some(elem_i), Some(elem_j)) = (
                    self.elems.get(i),
                    self.elems.get(j)
                ) {
                    if elem_i.criterion(elem_j) < self.cutoff {
                        // Modify both sides symmetrically
                        self.elems[i].nb.push(j);
                        self.elems[j].nb.push(i);
                    }
                }
            }
        }
    }

    /// QUESTION 3: Parallel version using rayon
    /// Uses two-phase approach: collect results first, then apply mutations
    pub fn build_lists_parallel(&mut self) {
        let nelems = self.get_nelems();

        // Phase 1: Read-only collection of neighbor pairs (parallel-safe)
        let neighbors: Vec<Vec<usize>> = self.elems.par_iter().enumerate()
            .map(|(i, elem_i)| {
                elem_i.neighbors(nelems, &self.elems, self.cutoff)
            })
            .collect::<Vec<_>>();

        // Phase 2: Apply mutations sequentially (or with atomic operations)
        for (i, neighbor_list) in neighbors.into_iter().enumerate() {
            self.elems[i].nb = neighbor_list;
        }
    }
}

impl B {
    /// Helper method to find all neighbors for a given element
    fn neighbors(&self, nelems: usize, elems: &[B], cutoff: f64) -> Vec<usize> {
        (0..nelems)
            .filter_map(|j| {
                if j != self_rust_index(elems, self) { // avoid self-comparison
                    elems.get(j)
                } else {
                    None
                }
            })
            .zip(0..nelems)
            .filter_map(|(elem_j, j)| {
                if self.criterion(elem_j) < cutoff {
                    Some(j)
                } else {
                    None
                }
            })
            .collect()
    }
}

/// Helper to find index of element (used for avoiding self-comparison)
fn self_rust_index(elems: &[B], self_elem: &B) -> usize {
    elems.iter()
        .position(|e| e as *const _ == self_elem as *const _) // raw ptr comparison for identity
        .unwrap_or(0)
}

fn main() {
