    let mut a = A {
        elems: vec![
            B::new([0.0, 0.0, 0.0]),
            B::new([1.0, 0.0, 0.0]),
            B::new([0.5, 0.5, 0.0]),
            B::new([10.0, 10.0, 10.0]), // far away
        ],
        cutoff: 2.0, // squared cutoff (~1.414 actual distance)
    };

    println!("\n=== Question 1: Safe Version (no unsafe) ===");
    a.build_lists_safe();
