                    let ty = ((-cube_size.y - (ray_origin.y - cube_center.y)) * (if ray_direction.y > 0.0 { 1.0 } else { -1.0 })) / ray_direction.y.abs();
                    let tx = ((-cube_size.x - (ray_origin.x - cube_center.x)) * (if ray_direction.x > 0.0 { 1.0 } else { -1.0 })) / ray_direction.x.abs();
                    let tz = ((-cube_size.z - (ray_origin.z - cube_center.z)) * (if ray_direction.z > 0.0 { 1.0 } else { -1.0 })) / ray_direction.z.abs();

                    let t = [ty, tx, tz].iter().copied().filter(|&t| t >= 0.0 && t <= max_distance).min_by(|a, b| a.partial_cmp(b).unwrap()).unwrap_or(max_distance);

                    let intersection = ray_origin + ray_direction * t;

                    if t < max_distance {
                        closest = Some((intersection, cube_global));
                    }
