enum_dispatch = "0.3"",
"main.rs": "//! Solution to the enum_dispatch cross-module dilemma.
//! 
//! DESIGN NOTE:
//! The `enum_dispatch` macro requires the Trait and the Enum to be defined 
//! within the **same Cargo Crate**. While they can reside in different modules
//! (like `al` and `bl` below), they cannot be separated into distinct crates
//! without violating this macro constraint.
//! 
//! To resolve this in a multi-crate environment, you must move the Enum definition
//! (Item) into the crate that defines the Trait (al), even if it introduces
//! dependencies on concrete types from il. This effectively makes `al` the
//! orchestration crate for the interface variations.";

use enum_dispatch::enum_dispatch;

/// Layer: Abstract Logic (Traits)
mod al {
    /// The core service trait requiring static dispatch capability.
    pub trait Rest {
        fn start(&self);
        fn stop(&self);
    }
}

/// Layer: Implementation Logic (Concrete Structs)
mod il {
    use super::al::Rest;

    pub struct Foo;
    pub struct Boo;

    impl Rest for Foo {
        fn start(&self) {
            println!("Foo Service Started");
        }
        fn stop(&self) {
            println!("Foo Service Stopped");
        }
    }

    impl Rest for Boo {
        fn start(&self) {
            println!("Boo Service Started");
        }
        fn stop(&self) {
            println!("Boo Service Stopped");
        }
    }
}

/// Layer: Business Logic (Usage & Composition)
mod bl {
    use super::al::Rest;
    use super::il::{Foo, Boo};

    /// The composed enum utilizing static dispatch.
    /// 
    /// CONSTRAINT WORKAROUND: 
    /// In a strict multi-crate setup, this Enum MUST be defined in crate `al` 
    /// because `enum_dispatch` does not support cross-crate trait binding.
    /// Here, they share the same crate, so modular separation works.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }
}

fn main() {
    // Usage in business layer
    let foo_instance = bl::Item::Foo(il::Foo);
    let boo_instance = bl::Item::Boo(il::Boo);

    // Polymorphic calls with static dispatch performance
    foo_instance.start();
    foo_instance.stop();

    boo_instance.start();
    boo_instance.stop();

    println!("\nSystem executed successfully with static dispatch!");
}" 
}

