/// Tokenize a shell command line respecting single quotes.
/// 
/// - Whitespace separates tokens in unquoted sections
/// - Content inside single quotes is preserved exactly (including spaces)
/// - Adjacent quoted and unquoted content without separating whitespace merges
fn tokenize(s: &str) -> Vec<String> {
    s.split("'")
     .enumerate()
     .flat_map(|(i, chunk)| {
         if i % 2 == 0 {
             // Unquoted section: split by whitespace runs
             chunk.chars()
                  .group_by(|c| *c == ' ')
                  .into_iter()
                  .map(|(is_space, chars)| (
                      is_space,
                      chars.collect::<String>()
                  ))
                  .collect::<Vec<_>>()
         } else {
             // Quoted section: preserve exactly as one token
             vec![(false, chunk.to_string())]
         }
     })
     .group_by(|(_, s)| !s.chars().all(|c| c == ' '))
     .into_iter()
     .map(|(_, group)| group.map(|(_, c)| c).join(""))
     .filter(|s| !s.chars().all(|c| c == ' '))
     .collect()
}

