            .unwrap_or(base_path)
            .join(parts[0])
    };

    let content = fs::read_to_string(&ref_file)?;
    let ref_value: Value = from_str(&content)?;

    let resolved = if parts.len() > 1 {
        // Has JSON pointer like #/p_list
        resolve_pointer(&ref_value, &parts[1..].join("#"))?
    } else {
        // No pointer, take entire file content
        ref_value
    };

    // Replace the entire object with resolved value
    *obj = serde_json::Map::default();
    if let Value::Object(o) = resolved {
        for (k, v) in o {
            obj.insert(k, v);
        }
    }

    Ok(())
}

// Resolve JSON Pointer within a value
fn resolve_pointer(value: &Value, pointer: &str) -> Result<Value, Box<dyn std::error::Error>> {
    if pointer.is_empty() {
        return Ok(value.clone());
    }

    let parts: Vec<&str> = pointer.trim_start_matches('/').split('/').collect();
    let mut current = value;

    for part in parts {
        let key = part.replace("~1", "/").replace("~0", "~");
        current = match current {
            Value::Object(map) => map.get(&key).cloned().ok_or("pointer not found")?,
            Value::Array(arr) => {
                let idx: usize = key.parse().map_err(|_| "invalid array index")?;
                arr.get(idx).cloned().ok_or("index out of bounds")?
            },
            _ => return Err("cannot descend into non-object/array".into()),
        };
    }

    Ok(current.clone())
}

fn main() {
    let json_data = fs::read_to_string("b.json").expect("failed to read from b.json");
    let mut value: Value = from_str(&json_data).expect("initial parse failed");

    let base_path = PathBuf::from("b.json");
    resolve_ref(&mut value, &base_path).expect("ref resolution failed");

    let a_obj: A = from_str(&value.to_string()).expect("deserialization failed");

    for p in &a_obj.path_list {
        println!("{}", p);
    }
}"
}

