    /// Q1 & Q2 Solution: Safe Sequential Implementation
    /// Uses index-based access to avoid unsafe pointers.
    /// Iterates j > i to ensure symmetry without double counting work.
    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();

        // First, clear/initialize all neighbor lists
        for elem in self.elems.iter_mut() {
            elem.nb.clear();
        }

        // Second, iterate pairs (i, j) where j > i
        for i in 0..nelems {
            // Access element i mutably
            let elem_i = &mut self.elems[i];

            for j in (i + 1)..nelems {
                // Access element j immutably for check
                // This is safe because i != j
                let elem_j = &self.elems[j];

                if elem_i.criterion(elem_j) < self.cutoff {
                    elem_i.nb.push(j);

                    // Symmetric update: push i to j's list
                    // We do this immediately after the first push.
                    // The mutable borrow of elems[i] ends at the semi-colon,
                    // allowing us to borrow elems[j] mutably next.
                    self.elems[j].nb.push(i);
                }
            }
        }
    }

    /// Q3 Solution: Parallel Implementation
    /// Uses Rayon. Since par_iter_mut splits the vector into exclusive chunks,
    /// cross-chunk updates (writing to elem_j.nb while processing elem_i) are
    /// restricted. We solve this by:
    /// 1. Reading all positions immutably in parallel.
    /// 2. Collecting matching pairs.
    /// 3. Applying updates sequentially.
    pub fn build_lists_parallel(&mut self) {
        let nelems = self.get_nelems();

        // Prepare output buffers
        let mut new_nb = vec![Vec::new(); nelems];

        // Parallel phase: Find all pairs (i, j) that meet criteria
        // We use par_iter on indices to avoid synchronization issues with the Vec<B>
        // Note: B is Sync, so par_iter on the slice works.
        let pairs: Vec<(usize, usize)> = (0..nelems)
            .into_par_iter()
