        for elem in self.elems.iter_mut() {
            elem.nb.clear();
        }

        // Sequential phase: Build symmetric lists from pairs
        for (i, j) in pairs {
            self.elems[i].nb.push(j);
            self.elems[j].nb.push(i);
        }
    }
