  "main.rs": "//! Minimal Example: Safe Concurrent PTY Access with expectrl
//! 
//! This solves the "read thread holds mutex" deadlock by:
//! 1. Moving the `expectrl::Session` entirely into a dedicated worker thread.
//! 2. Communicating writes via `mpsc` channels instead of locking a shared mutex.
//! 3. Allowing the worker thread to manage its own read/write lifecycle without external interference.

use expectrl::Session;
use std::io::{self, Read, Write};
use std::sync::mpsc::{self, Receiver, Sender, TryRecvError};
use std::thread;
use std::time::Duration;

/// Commands sent to the PTY Worker Thread
enum PtyCommand {
    Write(String),
    Kill,
}

/// Handle to communicate with the running PTY Agent
pub struct PtyAgent {
    _join_handle: Option<thread::JoinHandle<()>>,
    tx: Sender<PtyCommand>,
}

impl PtyAgent {
    /// Spawns the agent process inside a dedicated worker thread.
    pub fn new(command: &str) -> io::Result<Self> {
        println!("Starting agent with command: {}", command);
        let (tx, rx): (Sender<PtyCommand>, Receiver<PtyCommand>) = mpsc::channel();

        // Initialize expectrl session
        let mut session = Session::spawn(vec![command])
            .map_err(|e| io::Error::new(io::ErrorKind::Other, e.to_string()))?;

        // Optional: Configure environment
        session
            .set_env("TERM", "xterm-256color")
            .ok();

        // Spawn the Worker Thread that EXCLUSIVELY owns the Session
        let handle = thread::spawn(move || {
            let mut buf = [0u8; 1024];
            println!(!"PTY Worker Thread Started");

            loop {
                // --- WRITE PATH (Prioritized via Timeout) ---
                // Check if the frontend/Tauri has something to send.
                // We use recv_timeout to avoid stalling indefinitely if there's no input,
                // allowing us to attempt reading from PTY occasionally.
                // NOTE: For production, consider using non-blocking IO or async RT (tokio)
                // to interleave reads and writes seamlessly without arbitrary timeouts.
                match rx.recv_timeout(Duration::from_millis(50)) {
                    Ok(PtyCommand::Write(data)) => {
                        print!("[WORKER]: Sending to PTY: \"{}\"\r", data);
                        if let Err(e) = session.write_all(data.as_bytes()) {
                            eprintln!(!"Failed to write to PTY: {}", e);
                            break;
                        }
                        continue;
                    },
                    Ok(PtyCommand::Kill) => {
                        println!(!"[WORKER]: Killing agent...");
                        break;
                    },
                    Err(TryRecvError::Empty) => {
                        // No writes pending, proceed to read PTY output
                    },
                    Err(TryRecvError::Disconnected) => {
                        println!(!"[WORKER]: Channel disconnected, stopping.");
                        break;
                    }
                }

                // --- READ PATH ---
                // Blocking read. Because we are the sole owner of the Session,
                // there is no mutex contention. Other threads can't lock this.
                // If the child process blocks waiting for input, this thread blocks here.
                // This is acceptable for the pattern as writes are queued via channel
                // and processed when this thread becomes available or via higher-priority polling in Async.
                match session.read(&mut buf) {
                    Ok(n) => {
                        if n == 0 {
                            print!(["[AGENT] TERMINATED\n"]);
                            break;
                        }
                        // Forward output to frontend (simulated here via stdout)
                        if let Ok(out) = String::from_utf8(buf[..n].to_vec()) {
                            print!("[OUTPUT]: {}", out);
                            io::stdout().flush().ok();
                        }
                    },
                    Err(_) => {
                        // EOF or error
                        println!(!"[WORKER]: Read error or EOF.");
                        break;
                    }
                }
            }
        });

        Ok(Self {
            _join_handle: Some(handle),
            tx,
        })
    }

    /// Sends input (keystrokes) to the agent.
    /// This does NOT block waiting for output, nor does it fight for a mutex.
    pub fn send_input(&self, input: &str) {
        let cmd = PtyCommand::Write(format!("{}\r", input)); // Add CR for enter behavior
        if self.tx.send(cmd).is_err() {
            eprintln!("Failed to send input: Agent is down");
        }
    }

    pub fn kill(&self) {
        let _ = self.tx.send(PtyCommand::Kill);
    }
}

fn main() -> io::Result<()> {
    // 1. Spawn an interactive shell
    // Using 'bash' to demonstrate input/output interactivity
    let agent = PtyAgent::new("bash")?;

    // 2. Simulation: Wait a moment for shell to initialize
    println!("\n--- Simulating User Interaction ---\n");
    thread::sleep(Duration::from_secs(1));

    // 3. Send command: Echo Hello
    agent.send_input("echo 'Hello from Tauri Agent'");
    thread::sleep(Duration::from_millis(500));

    // 4. Send command: Read input (Simulates Gemini/Codex waiting)
    agent.send_input("echo 'Waiting for name...' && read name && echo 'Hello $name'");
    thread::sleep(Duration::from_millis(500));

    // 5. Type response
    agent.send_input("World");

    thread::sleep(Duration::from_millis(500));

    // 6. Exit
    agent.send_input("exit");
    thread::sleep(Duration::from_millis(500));

    println!("\n--- Demo Finished ---\n");
    Ok(())
}",
}

