name = "origin-check-ws"
version = "0.1.0"
edition = "2021"

[dependencies]
axum = "0.7"
tokio = { version = "1", features = ["full"] }
http = "0.2"",
  "main.rs": "use axum::{
    body::Body,
    extract::{ws::{WebSocket, WebSocketUpgrade}, Request},
    middleware::Next,
    response::Response,
    routing::get,
    Router,
};
use http::{header, StatusCode};
use std::net::SocketAddr;
use std::sync::LazyLock;

const ALLOWED_ORIGIN: &str = "https://www.example.com";

// Middleware to validate the Origin header before allowing the request to proceed.
// This is crucial for WebSockets because CORS doesn't automatically block the upgrade.
async fn validate_origin<B>(
    mut req: Request<B>,
    next: Next<B>,
) -> Result<Response, StatusCode>
where
    B: Send + Sync + 'static,
{
    if let Some(origin) = req.headers().get(header::ORIGIN) {
        if let Ok(origin_str) = origin.to_str() {
            // Check if origin is in the allowed list
            if origin_str != ALLOWED_ORIGIN {
                eprintln!("Rejected invalid origin: {}", origin_str);
                return Err(StatusCode::FORBIDDEN);
            }
        }
    } else {
        // WebSockets usually require an Origin header for security verification.
        // Reject if missing.
        eprintln!("Rejected request missing Origin header");
        return Err(StatusCode::BAD_REQUEST);
    }

    // If validation passes, continue with the request
    Ok(next.run(req).await)
}

async fn client_handler(ws: WebSocketUpgrade) -> impl axum::response::IntoResponse {
    ws.on_upgrade(|socket| socket_handler(socket)).into_response()
}

async fn socket_handler(mut socket: WebSocket) {
    // Simple echo loop
    while let Some(msg) = socket.recv().await {
        let _ = socket.send(msg).await;
    }
}

#[tokio::main]
async fn main() {
    let app = Router::new()
        // The /client/:id route will only accept connections if the Origin header matches
        .route("/client/:id", get(client_handler))
        .layer(axum::middleware::from_fn(validate_origin));

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("Listening on {}", addr);

    // Spawn the listener
    axum::serve(
        tokio::net::TcpListener::bind(addr).await.unwrap(),
        app.into_make_service(),
    )
    .await
    .unwrap();
}"
}

