#[derive(Debug)]
pub struct Context(i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<dyn for<'a> Fn(&'a mut Context) -> Pin<Box<dyn futures::Future<Output = ()> + Send + 'a>> + Send>,
    },
