/// Helper function to send async workloads between threads
/// 
/// This wrapper accepts any closure that takes a mutable reference to Context
/// and returns a Send Future, making it easier to create async workloads.
pub fn with_context_async(
    work_sender: &mpsc::Sender<InnerAsyncEvent>,
    block: impl for<'a> Fn(&'a mut Context) -> Pin<Box<dyn futures::Future<Output = ()> + Send + 'a>> + Send + 'static,
) -> Result<(), mpsc::SendError<InnerAsyncEvent>> {
    work_sender.send(InnerAsyncEvent::DoWithContext { block: Box::new(block) })
}

#[tokio::main]
async fn main() {
    let (sender, receiver) = mpsc::channel::<InnerAsyncEvent>();

    // Spawn worker thread/task
    let worker = tokio::spawn(async move {
        let mut ctx = Context(0);
        println!("Worker started with initial context value: {}", ctx.0);

        loop {
            match receiver.recv() {
                Ok(event) => match event {
                    InnerAsyncEvent::DoWithContext { block } => {
                        let fut = block(&mut ctx);
                        fut.await;
                    }
                }
                Err(_) => break, // Sender dropped, exit gracefully
            }
        }
        println!("Worker finished with final context value: {}", ctx.0);
    });

    // Send some async work using our nice helper
    let result = with_context_async(&sender, |ctx| {
        Box::pin(async move {
            println!("Task 1 running... old value: {}", ctx.0);
            ctx.0 += 1;
            println!("Task 1 completed. New value: {}", ctx.0);
        })
    });

    assert!(result.is_ok());

    // Wait a bit for task to execute
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    // Send another workload
    with_context_async(&sender, |ctx| {
        Box::pin(async move {
            println!("Task 2 running... old value: {}", ctx.0);
            ctx.0 += 10;
            println!("Task 2 completed. New value: {}", ctx.0);
        })
    }).unwrap();

    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    // Send workload that demonstrates async wait
    with_context_async(&sender, |ctx| {
        Box::pin(async move {
            println!("Task 3 starting async operation...");
            tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
            ctx.0 += 100;
            println!("Task 3 async operation complete. Value: {}", ctx.0);
        })
    }).unwrap();

    // Drop sender to signal worker to exit
    drop(sender);

    // Wait for worker to finish
    worker.await.expect("Worker panicked");

    println!("All tasks completed successfully!");
