// Shared context simulating Pingora/Proxy Request Context
#[derive(Clone)]
struct RequestContext {
    // Crucial: Keep the Root Span handle alive for the duration of the request lifecycle.
    // This allows child stages to link back to it even if they run on different tasks/threads.
    pub root_span: Arc<tracing::Span>,
}

impl RequestContext {
    fn new(root_span: tracing::Span) -> Self {
        Self {
            root_span: Arc::new(root_span),
        }
    }
}

// Trait simulating Pingora handler stages
trait ProxyHandler: Sync + Send {
    async fn stage_1(&self, ctx: &RequestContext);
    async fn stage_2(&self, ctx: &RequestContext);
}

