#[async_trait]
impl ProxyHandler for DemoHandler {
    async fn stage_1(&self, ctx: &RequestContext) {
        // Clone the parent span from context
        let parent_span = Arc::clone(&ctx.root_span);

        // Create a new stage span, explicitly linking it to the parent using `parent: &span`
        // Even if this runs on a different thread or later, the lineage is preserved.
        let _guard = tracing::info_span!("Stage 1", parent: &parent_span).entered();

        println!("Processing Stage 1...");
        sleep(Duration::from_millis(50)).await;
        tracing::info!("Stage 1 complete");
    }

    async fn stage_2(&self, ctx: &RequestContext) {
        let parent_span = Arc::clone(&ctx.root_span);

        // Link Stage 2 to the SAME Root Span as Stage 1
        let _guard = tracing::info_span!("Stage 2", parent: &parent_span).entered();

        println!("Processing Stage 2...");
        sleep(Duration::from_millis(50)).await;

        // Simulating further downstream/upstream instrumentation
        let upstream_guard = tracing::info_span!("Upstream", parent: &tracing::Span::current()).entered();
        tracing::info!("Upstream fetch");
        drop(upstream_guard);

        tracing::info!("Stage 2 complete");
    }
}

#[tokio::main]
async fn main() {
    // 1. Initialize OpenTelemetry Provider with stdout exporter
    let telemetry = opentelemetry_sdk::trace::TracerProvider::builder()
        .with_simple_exporter(stdout::new_pipeline().build().unwrap())
        .with_sampler(Sampler::AlwaysOn)
