    let otel_layer = tracing_opentelemetry::layer()
        .with_tracer(tracer.clone());

    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new("debug"));

    tracing_subscriber::registry()
        .with(filter)
        .with(otel_layer)
        .with(
            tracing_subscriber::fmt::layer()
                .with_target(true)
                .with_thread_ids(false)
                .without_time(),
        )
        .init();

    println!("Starting Request Lifecycle Simulation...\n");

    // 3. Create Root Request Span
    let request_span = tracing::info_span!("Request", request_id = 12345);
    let ctx = RequestContext::new(request_span);

    // 4. Execute the lifecycle
    // Note: The root span remains open until dropped (at end of scope below),
    // keeping it as the active parent for any spawned tasks using its handle.
    {
        let _request_guard = ctx.root_span.enter();
        tracing::info!("Request received");

        // Spawn handlers to simulate Pingora calling stages asynchronously/independently
        // Passing the shared Context ensures they have access to the Parent Span handle.
        let task_1 = tokio::spawn(async move { DemoHandler.stage_1(&ctx).await });
