        let _ = task_1.await;
        let _ = task_2.await;

        tracing::info!("Request completed");
    }
    // Dropping `ctx` implicitly drops the last ref to `root_span`, closing the Root Span.

    // Give exporter time to flush
    sleep(Duration::from_millis(200)).await;
