            APIVersion::V2 => write!(f, "v2"),
        }
    }
}

#[derive(Debug)]
pub struct ApiVersionHeader(pub APIVersion);

impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(
        parts: &mut RequestParts<S>,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        let name = HeaderName::from_static("x-api-version");
        let value = parts.headers.get(&name).ok_or_else(|| {
            APIError::missing_header("X-Api-Version")
        })?;

        let s = value.to_str().map_err(|_| {
            APIError::missing_header("X-Api-Version")
        })?;

        let version = APIVersion::parse(s).map_err(|err| {
            APIError::invalid_input(&format!("invalid X-Api-Version: {}", err))
        })?;

        Ok(ApiVersionHeader(version))
    }
}

// Validated JSON extractor
pub struct ValidatedJson<T>(pub T);

impl<T, S> FromRequest<S> for ValidatedJson<T>
where
    T: DeserializeOwned + Validate + Send,
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request(
        req: Request,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        let json: Json<T> = Json::<T>::from_request(req, _state)
            .await
            .map_err(|_| APIError::invalid_input("invalid JSON"))?;

        let payload = json.0;
        payload.validate().map_err(|e| {
            APIError::invalid_input(&format!("validation failed: {}", e))
        })?;

        Ok(ValidatedJson(payload))
    }
}

// Handler with multiple extractors
async fn revoke_user_handler(
    api_version_header: ApiVersionHeader,
    access_claims: AccessClaims,
    validatd_json: ValidatedJson<RevokeUser>,
) -> impl IntoResponse {
    tracing::info!("api version: {}", api_version_header.0);

    if access_claims.sub != validatd_json.0.user_id {
        // Admin check
        access_claims.validate_role_admin()?;
    }

    tracing::info!("revoking tokens for user: {}", validatd_json.0.user_id);

    Ok(Json(serde_json::json!({
        "message": "success",
        "user_id": validatd_json.0.user_id
    })))
}

// Routes
fn routes() -> Router<Arc<SharedState>> {
    Router::new()
        .route("/auth/revoke-user", post(revoke_user_handler))
}

// Start server
#[tokio::main]
async fn main() {
    tracing_subscriber::init();

    let state = Arc::new(SharedState {
        name: "Axum Validation Example".to_string(),
    });

    let app = Router::new()
        .nest("/api/v1", routes())
        .layer(TraceLayer::new_for_http())
        .with_state(state);

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .unwrap();

    tracing::info!("Listening on {:?}", listener.local_addr());

    axum::serve(listener, app).await.unwrap();
}"
}

