{
  "Cargo.toml": "[package]
name = "rehydrate-span-example"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
tracing = "0.1"
tracing-subscriber = { version = "0.3", features = ["env-filter"] }
",
  "main.rs": "// Self-contained example demonstrating how to rehydrate a tracing span
// across async boundaries and simulated callbacks (like Pingora stages)

use std::sync::Arc;
use tokio::time::{sleep, Duration};
use tracing::{info, instrument, Instrument, Span};
use tracing_subscriber::fmt::format::FmtSpan;
use tracing_subscriber::{layer::SubscriberExt, Registry};

// Represents shared context that gets passed between stages
#[derive(Clone)]
pub struct RequestContext {
    pub request_id: u64,
    // Store the parent span handle so we can reattach to it
    pub parent_span: Option<Arc<Span>>,
}

impl RequestContext {
    pub fn new(request_id: u64) -> Self {
        // Capture the currently active span
        let parent_span = if let Some(span) = Span::current() {
            Arc::new(span.clone())
        } else {
            None
        };
        Self {
            request_id,
            parent_span,
        }
    }

    // Method to execute code within the context of the parent span
    pub async fn execute_in_parent<F, Fut>(&self, f: F) -> Fut
    where
        F: FnOnce() -> Fut + Send + 'static,
        Fut: FutureOutput,
    {
        if let Some(ref parent_span) = self.parent_span {
            parent_span.in_scope(|| async move { f() }).await
        } else {
            f()
        }
    }
}

trait FutureOutput: {}
impl<T> FutureOutput for T {}

// Simulates Pingora trait method - Stage 1
#[instrument(name = "stage1")]
async fn stage_one(ctx: &RequestContext) {
    info!(request_id = ctx.request_id, "Starting stage 1");
    sleep(Duration::from_millis(50)).await;
    info!(request_id = ctx.request_id, "Finished stage 1");
}

// Simulates Pingora trait method - Stage 2
#[instrument(name = "stage2")]
async fn stage_two(ctx: &RequestContext) {
    info!(request_id = ctx.request_id, "Starting stage 2");
    sleep(Duration::from_millis(30)).await;
    info!(request_id = ctx.request_id, "Finished stage 2");
}

// Simulates upstream call
#[instrument(name = "upstream")]
async fn upstream_call(ctx: &RequestContext) {
    info!(request_id = ctx.request_id, "Making upstream call");
    sleep(Duration::from_millis(70)).await;
    info!(request_id = ctx.request_id, "Upstream call completed");
}

// Entry point simulating a full request lifecycle
#[instrument(name = "request")]
async fn process_request(request_id: u64) {
    info!(request_id, "Processing request started");

    // Initialize context capturing the current span
    let mut ctx = RequestContext::new(request_id);

    // Stage 1 - executes while parent span is still active
    ctx.execute_in_parent(async {
        stage_one(&ctx).await;
    })
    .await;

    // Small gap to simulate asynchronous scheduling
    sleep(Duration::from_millis(10)).await;

    // Stage 2 - rehydrates parent span before executing
    ctx.execute_in_parent(async {
        stage_two(&ctx).await;
    })
    .await;

    // Upstream call - also under parent span via rehydration
    ctx.execute_in_parent(async {
        upstream_call(&ctx).await;
    })
    .await;

    info!(request_id, "Processing request finished");
}

#[tokio::main]
async fn main() {
    // Set up tracing subscriber
    let subscriber = Registry::default().with(
        tracing_subscriber::fmt::layer()
            .with_thread_ids(true)
            .with_span_events(FmtSpan::NEW | FmtSpan::CLOSE)
            .pretty(),
    );
    tracing::subscriber::set_global_default(subscriber).expect("failed to set subscriber");

    // Simulate multiple requests
    let request_tasks = vec![
        process_request(1),
        process_request(2),
        process_request(3),
    ];

    // Run them concurrently
    let handles: Vec<_> = request_tasks.into_iter().map(|task| tokio::spawn(task)).collect();

    // Wait for all to complete
    for handle in handles {
        handle.await.expect("Task failed");
    }

    info!("All requests processed");
}",
  "explanation": /*
This solution demonstrates:

1. **Storing Parent Span**: `Span::current()` captures the active span, wrapped in `Arc` for sharing across async boundaries.

2. **Rehydrating Span**: `span.in_scope(closure)` temporarily makes the stored span active within the closure, ensuring child spans nest correctly.

3. **Request Context Pattern**: Similar to Pingora's context passing, we store the span in a context object that travels between stages.

4. **Expected Output**: Shows proper span hierarchy:
   - Request (parent) span encompasses all stages
   - Stage 1, 2, and upstream spans nest under their respective activations

To use: Save files in your project directory and run `cargo run`. Install `cargo-expand` to inspect the generated macros if needed.
*/
}

