/// Custom event handler that deletes trailing whitespace and inserts a character,
/// then ensures cursor is positioned AFTER the inserted character.
struct WhitespaceCleanupHandler {
    insert: String,
}

impl WhitespaceCleanupHandler {
    fn new(insert: char) -> Self {
        let insert = String::from(insert);
        WhitespaceCleanupHandler { insert }
    }
}

impl rustyline::conditional_event_handler::ConditionalEventHandler for WhitespaceCleanupHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &rustyline::event_context::EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Find trailing whitespace before cursor
        let mut whitespace_len = 0;
        for ch in line[..pos].chars().rev() {
            if ch.is_whitespace() {
                whitespace_len += ch.len_utf8();
            } else {
                break;
            }
        }

        if whitespace_len > 0 {
            // Move back to delete whitespace, then insert our character
            // The trick: Use Replace with movement to go back, which leaves cursor
            // after the new character
            let movement = Movement::BackwardByte(whitespace_len as RepeatCount);
            Some(Cmd::Replace(movement, Some(self.insert.clone())))
        } else {
            // No whitespace to delete, just insert normally
            None // Let default handling occur
        }
    }
}

fn bind_cleanup_handler(editor: &mut Editor<(), ()>, key: char) {
    let event = KeyEvent::new(key, rustyline::Modifiers::NONE);
    let handler = WhitespaceCleanupHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(event, handler).unwrap();
}

