/// - "2025-08-02T17:35:41.409" (with fractional seconds)
pub fn date_string_to_int(d: &str) -> Result<i64, String> {
    // RFC3339 is compatible with the format and handles optional fractional seconds
    match DateTime::<Utc>::parse_from_rfc3339(d) {
        Ok(dt) => Ok(dt.timestamp()),
        Err(_) => {
            // Fallback to specific format patterns
            let formats = [
                "%Y-%m-%dT%H:%M:%S",
                "%Y-%m-%dT%H:%M:%S%.f",
            ];

            for format in formats {
                if let Ok(dt) = DateTime::parse_from_str(d, format) {
                    return Ok(dt.timestamp());
                }
            }

            Err(format!("Failed to parse date: {}", d))
        }
    }
}

/// Alternative: Returns a DateTime<Utc> instead of i64 timestamp
pub fn date_string_to_datetime(d: &str) -> Result<DateTime<Utc>, String> {
    DateTime::<Utc>::parse_from_rfc3339(d).map_err(|e| format!("{}", e))
}

fn main() {
    let test_dates = vec![
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
    ];

    println!("=== Testing date_string_to_int ===\n");

    for date_str in &test_dates {
        match date_string_to_int(date_str) {
            Ok(timestamp) => println!("✓ {:<35} -> {}", date_str, timestamp),
            Err(e) => println!("✗ {:<35} -> Error: {}", date_str, e),
        }
    }

    println!("\n=== Testing date_string_to_datetime ===\n");

    for date_str in &test_dates {
        match date_string_to_datetime(date_str) {
            Ok(dt) => println!("✓ {:<35} -> {}", date_str, dt),
            Err(e) => println!("✗ {:<35} -> Error: {}", date_str, e),
        }
    }
}"
}

