// N-dimensional array structure
#[derive(Debug, Clone)]
pub struct Array<T> {
    pub store: Vec<T>,
    pub dims: Vec<usize>,
}

impl<T> Array<T> {
    /// Create a new n-dimensional array filled with default values
    pub fn new(dims: Vec<usize>, default: T) -> Self
    where
        T: Clone,
    {
        let len = dims.iter().product();
        let store = vec![default; len as usize];
        Array { store, dims }
    }

    /// Compute flat index from multi-dimensional indices
    fn flat_index(&self, indices: &[usize]) -> usize {
        let mut index = 0;
        let mut stride = 1;
        for (&dim, &i) in self.dims.iter().rev().zip(indices.iter().rev()) {
            index += i * stride;
            stride *= dim;
        }
        index
    }

    /// Immutable indexing
    #[allow(unused)]
    fn get(&self, indices: &[usize]) -> &T {
        let flat_idx = self.flat_index(indices);
        &self.store[flat_idx]
    }

    /// Mutable indexing
    #[allow(unused)]
    fn get_mut(&mut self, indices: &[usize]) -> &mut T {
        let flat_idx = self.flat_index(indices);
        &mut self.store[flat_idx]
    }
}

