// IMMUTABLE ITERATOR - WORKS FINE
// This compiles and works correctly because immutable references can be
// safely returned while the iterator holds &Array<T>
// ===========================================================================

#[derive(Debug)]
pub struct ArrayImmutableIterator<'a, T> {
    array: &'a Array<T>,
    current_indices: Vec<usize>,
    dims: Vec<usize>,
    finished: bool,
}

impl<'a, T> ArrayImmutableIterator<'a, T> {
    pub fn new(array: &'a Array<T>) -> Self {
        let dims = array.dims.clone();
        let num_elements: usize = dims.iter().product();
        let current_indices = vec![0; dims.len()];

        ArrayImmutableIterator {
            array,
            current_indices,
            dims,
            finished: num_elements == 0,
        }
    }
}

impl<'a, T> Iterator for ArrayImmutableIterator<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.finished {
            return None;
        }

        let indices = self.current_indices.clone();
        let value = self.array.get(&indices);

        // Increment indices (rightmost first)
        for i in (0..self.dims.len()).rev() {
            self.current_indices[i] += 1;
            if self.current_indices[i] < self.dims[i] {
                break;
            }
            self.current_indices[i] = 0;
            if i == 0 {
                self.finished = true;
            }
        }

        Some((indices, value))
    }
}

// ===========================================================================
// MUTABLE ITERATOR SOLUTION
// Cannot use &'a mut Array<T> directly because next(&mut self) creates
// conflicting borrows. Instead, we take the array temporarily via closure.
// ===========================================================================

/// Helper function that performs one mutation step
/// Returns None when iteration should stop
pub fn apply_to_array_mutable<F, T>(array: &mut Array<T>, mut f: F)
where
    F: FnMut(Vec<usize>, &mut T),
{
    if array.dims.is_empty() || array.store.is_empty() {
        return;
    }

    let dims = array.dims.clone();
    let num_elements: usize = dims.iter().product();

    for flat_idx in 0..num_elements {
        // Convert flat index back to multi-dimensional indices
        let mut temp = flat_idx;
        let mut indices = Vec::with_capacity(dims.len());
        for &dim in dims.iter().rev() {
            indices.push(temp % dim);
            temp /= dim;
        }
        indices.reverse();

        f(indices, &mut array.store[flat_idx]);
    }
}

// ===========================================================================
// MAIN - DEMONSTRATING THE DIFFERENT APPROACHES
// ===========================================================================

fn main() {
    println!("=== Array Iteration Lifetime Demonstration ===\n");

    // Create a 2x3 array
    let mut array = Array::new(vec![2, 3], 0);

    // ========================================
    // IMMUTABLE ITERATION - WORKS
    // ========================================
    println!("1. Immutable iteration (works):");
    for (indices, value) in ArrayImmutableIterator::new(&array) {
        println!("   Index {:?}: value = {}", indices, value);
    }

    // ========================================
    // MUTABLE ACCESS - WORKAROUND 1
    // Use closure-based iteration
    // ========================================
    println!("\n2. Mutable iteration via closure:");
    let mut count = 0u32;
    apply_to_array_mutable(&mut array, |indices, elem| {
        count += 1;
        *elem = count as u32;
        println!("   Index {:?}: set to {}", indices, count);
    });

    // ========================================
    // MUTABLE ACCESS - WORKAROUND 2
    // Iterate by index, then mutably borrow each element
    // ========================================
    println!("\n3. Another mutable access pattern (demonstration):");

    // Double all values
    for flat_idx in 0..array.store.len() {
        let mut_elem = &mut array.store[flat_idx];
        *mut_elem *= 2;
    }

    println!("   Final array contents: {:?}", array.store);

    // ========================================
    // WHY THE ORIGINAL CODE FAILED
    // ========================================
    println!("\n=== Why original mutable iterator failed ===");
    println!("Issue: next(&mut self) borrows the iterator mutably.");
    println!("When returning &'a mut T, Rust requires that the reference");
    println!("must live at least as long as the mutable borrow of self.");
    println!("But self (the iterator) only exists during the call to next().");
    println!("This creates a lifetime conflict that Rust's borrow checker detects.");
    println!("");
    println!("For immutable references, this works because multiple immutable");
    println!("borrows can coexist, so &'a T can be returned even during a &mut self borrow.");
    println!("");
    println!("For mutable references, Rust enforces exclusive access, preventing");
    println!("this pattern unless you use one of the workarounds shown above.");
}"
