{
  "Cargo.toml": "[package]
name = "file-server"
version = "0.1.0"
edition = "2021"

[dependencies]
hyper = { version = "1.0", features = ["full"] }
tokio = { version = "1", features = ["full"] }
http-body-util = "0.1"
hyper-util = { version = "0.1", features = ["tokio"] }",
  "main.rs": "use std::path::PathBuf;
use std::fs::metadata;
use tokio::io::{self, AsyncReadExt};
use hyper::server::conn::http1;
use hyper::service::{make_service_fn, service_fn};
use hyper_util::rt::TokioIo;
use http_body_util::{BodyExt, Full, StreamBody};
use std::pin::Pin;
use futures_util::stream;

async fn handle(path: PathBuf) -> Result<hyper::Response<impl http_body::Body<Data = bytes::Bytes, Error = Infallible>>, hyper::Error> {
    // Check if file exists and get metadata
    let meta = match metadata(&path) {
        Ok(m) => m,
        Err(_) => return Ok(response_404()),
    };

    let file = match File::open(&path).await {
        Ok(f) => f,
        Err(_) => return Ok(response_404()),
    };

    // Get file size for Content-Length header
    let len = meta.len();

    // Create a chunked reader
    const CHUNK_SIZE: usize = 8 * 1024 * 1024; // 8MB chunks

    let mut buf = vec![0u8; CHUNK_SIZE];
    let mut offset: u64 = 0;
    let total_len = len;

    // Create stream that reads file in chunks
    let stream = stream::unfold((file, offset), move |(mut file, mut current_offset)| {
        Box::pin(async move {
            if current_offset >= total_len {
                return None;
            }

            let remaining = total_len.saturating_sub(current_offset);
            let to_read = CHUNK_SIZE.min(remaining as usize);

            match file.read_exact(&mut buf[..to_read]).await {
                Ok(_) => {
                    current_offset += to_read as u64;
                    Some(
                        (
                            bytes::Bytes::copy_from_slice(&buf[..to_read]),
                            (file, current_offset),
                        ),
                    )
                },
                Err(_) => None,
            }
        })
    });

    // Convert stream to Body
    let body = Body::from_stream(stream);

    let resp = Response::builder()
        .status(200)
        .header("Content-Type", "application/octet-stream")
        .header("Content-Length", len.to_string())
        .body(body)?;

    Ok(resp)
}

fn response_404() -> hyper::Response<Full<bytes::Bytes>> {
    Response::builder()
        .status(404)
        .body(Full::new(bytes::Bytes::from_static(b"Not Found")))
        .unwrap()
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));

    let make_svc = make_service_fn(|_conn| async {
        Ok::<_, hyper::Error>(service_fn(handle))
    });

    let server = Server::bind(&addr).serve(make_svc);

    println!("Serving static files from {}", std::env::current_dir()?.display());
    println!("Server listening on http://{}", addr);

    if let Err(err) = server.await {
        eprintln!("Server error: {}", err);
    }

    Ok(())
}",
