fn main() -> io::Result<()> {
    let mut stdout = io::stdout();

    // Enter raw mode
    terminal::enable_raw_mode()?;

    // Hide cursor and move to top-left
    queue!(stdout, cursor::Hide, cursor::MoveTo(0, 0))?;
    stdout.flush()?;

    let mut last_tick = Instant::now();
    let tick_rate = Duration::from_secs(1);
    let poll_timeout = Duration::from_millis(50); // Check events every 50ms

    loop {
        // Clear screen for fresh rendering
        queue!(stdout, terminal::Clear(terminal::ClearType::All))?;

        // Render real-time content
        let timestamp = chrono::Local::now().format("%Y-%m-%d %H:%M:%S").to_string();
        queue!(stdout, 
            style::SetForegroundColor(style::Color::White),
            style::Print(format!("\n  === TUI Event Loop Demo ===\n\n")),
            style::Print(format!("  Time: {}\n", timestamp)),
            style::Print(format!("  Tick Counter: {}\n", (Instant::now() - last_tick).as_secs())),
        )?;

        // Render instructions
        queue!(stdout,
            style::SetForegroundColor(style::Color::Cyan),
            style::Print("\n  Press 'q' to quit."),
            style::Print("\n  Other keys will be captured."),
            style::ResetColor,
        )?;
        stdout.flush()?;

        // Poll for events with timeout - NON-BLOCKING!
        let has_event = event::poll(poll_timeout)?;

        if has_event {
            // Process any pending events immediately
            while event::poll(Duration::from_millis(0))? {
                match event::read()? {
                    Event::Key(key) => {
                        if key.code == KeyCode::Char('q') {
                            break;
                        }

                        queue!(stdout,
                            style::Print(format!("\n  You pressed: {:?}\n", key.code)),
                            style::ResetColor,
                        )?;
