{
  "Cargo.toml": "[package]
name = "repl_example"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "14"",
  "main.rs": "use rustyline::{
    Cmd::Newline,
    DefaultEditor,
    Event,
    EventHandler,
    KeySeq,
    KeyEvent,
    Modifiers,
};

/// Simple helper to determine if the input code is syntactically complete.
/// For this example, we just count parentheses. 
/// In a real application, this would use your language parser.
fn is_complete(input: &str) -> bool {
    let mut open_parens = 0;
    let mut open_braces = 0;
    let mut open_brackets = 0;

    for c in input.chars() {
        match c {
            '(' => open_parens += 1,
            ')' => open_parens = open_parens.saturating_sub(1),
            '{' => open_braces += 1,
            '}' => open_braces = open_braces.saturating_sub(1),
            '[' => open_brackets += 1,
            ']' => open_brackets = open_brackets.saturating_sub(1),
            _ => {}
        }
    }

    open_parens == 0 && open_braces == 0 && open_brackets == 0
}

fn main() {
    let mut rl = DefaultEditor::new().unwrap();

    // Bind Ctrl+J to behave like Enter (Newline command).
    // This ensures that hitting Ctrl+J also submits the current logical line
    // allowing the main loop to switch the prompt.
    rl.bind_sequence(
        KeySeq(vec![KeyEvent::new('j', Modifiers::CTRL)]),
        EventHandler::Simple(Newline),
    );

    // Buffer to accumulate multiline input
    let mut accumulated_input = String::new();
    let mut is_multiline = false;

    println!("Multiline REPL (Press Ctrl+D to exit)");
    println!("Use Ctrl+J or Enter to submit lines.");

    loop {
        // Determine prompt based on whether we are continuing previous input
        let prompt = if is_multiline { "... " } else { ">>> " };

        match rl.readline(prompt) {
            Ok(line) => {
                // If this is a continuation, prepend a newline to join logically
                if !accumulated_input.is_empty() {
                    accumulated_input.push('\n');
                }
                accumulated_input.push_str(&line);

                // Check if the input is complete
                if is_complete(&accumulated_input) {
                    // Input is complete: execute here
                    println!("Executing:\n{}", accumulated_input);

                    // Clear state for next command
                    accumulated_input.clear();
                    is_multiline = false;
                    println!(); // Blank line for readability
                } else {
                    // Input is incomplete: mark as multiline to change prompt next iteration
                    is_multiline = true;
                }
            }
            Err(e) => {
                // Handle errors (Ctrl+C, Ctrl+D)
                match e {
                    rustyline::error::ReadlineError::Eof => {
                        println!("\nExiting...");
                        break;
                    }
                    rustyline::error::ReadlineError::Interrupted => {
                        // On Interrupt (Ctrl+C), discard accumulated input
                        accumulated_input.clear();
                        is_multiline = false;
                        println!("\nInterrupted.");
                        continue;
                    }
                    _ => {
                        eprintln!("Error: {:?}", e);
                        break;
                    }
                }
            }
        }
