/// to demonstrate the solution to the dependency cycle dilemma.
///
/// In a real project:
/// - The `al` module would be the `abstract_layer` crate.
/// - The `il` module would be the `implementation_layer` crate.
/// - The rest of `main.rs` represents the `business_layer` crate.
///
/// The key to avoiding the cycle is defining the #[enum_dispatch] enum 
/// in the Business Layer (bl), importing the Trait from Abstract Layer (al),
/// and the Concrete Types from Implementation Layer (il).
//
/// Dependencies:
/// al -> None
/// il -> al
/// bl -> al, il
///
/// This directionality prevents cycles.

use enum_dispatch::enum_dispatch;

/// --- Abstract Layer (al) ---
/// Defines the interface. Should not depend on concrete implementations.
pub mod al {
    /// A high-level network service trait.
    /// In your scenario, this contains ~20 methods.
    pub trait Rest {
        fn name(&self) -> &'static str;
        fn execute(&self) -> Result<String, String>;
    }
}

/// --- Implementation Layer (il) ---
/// Implements the trait from `al`. Depends on `al`.
/// Does NOT depend on `bl` (no enum definition here).
pub mod il {
    use crate::al::Rest;

    pub struct Foo;
    pub struct Boo;

    impl Rest for Foo {
        fn name(&self) -> &'static str {
            "Foo Service"
        }

        fn execute(&self) -> Result<String, String> {
            Ok("Foo executed".to_string())
        }
    }

    impl Rest for Boo {
        fn name(&self) -> &'static str {
            "Boo Service"
        }

        fn execute(&self) -> Result<String, String> {
            Ok("Boo executed".to_string())
        }
    }
}

/// --- Business Layer (bl) ---
/// Defines the dispatch Enum. Depends on `al` (for Trait) and `il` (for Variants).
/// The #[enum_dispatch] macro is placed HERE.
///
/// This satisfies the requirement: Trait and Enum do not need to be defined
/// in the SAME CRATE originally, they just need to be visible to the compiler
/// in the crate where the macro expands (which is 'bl').
/// 
/// If 'bl' is a separate crate, it simply depends on 'al' and 'il'.

#[enum_dispatch(crate::al::Rest)]
pub enum Item {
    Foo(il::Foo),
    Boo(il::Boo),
}

fn main() {
    // Construct instances of the implementation layer
    let foo_instance = il::Foo;
    let boo_instance = il::Boo;

    // Wrap them in the business layer enum
    let item_foo = Item::Foo(foo_instance);
    let item_boo = Item::Boo(boo_instance);

    // Use static dispatch derived from the trait
    println!("Item 1 Name: {}", item_foo.name());
    println!("Item 1 Result: {:?}", item_foo.execute());

    println!("Item 2 Name: {}", item_boo.name());
    println!("Item 2 Result: {:?}", item_boo.execute());

    // Demonstrate polymorphism without dynamic dispatch overhead
    let items: Vec<Item> = vec![
        Item::Foo(il::Foo),
        Item::Boo(il::Boo),
    ];

    for item in items {
        println!("Dispatched: {} -> {:?}", item.name(), item.execute());
    }
}
