            height: "100vh",
            display: "flex",
            justify_content: "center",
            align_items: "center",
            overflow: "auto",
            {children}
        }
    }
}

/// A draggable point component.
/// Instead of handling drag events entirely locally, it subscribes to
/// the global mouse position provided by DragProvider.
#[component]
fn Point(x: i32, y: i32) -> Element {
    // Internal state for the actual position of this point
    let mut pos_x = use_signal(|| x as f64);
    let mut pos_y = use_signal(|| y as f64);

    // Local flag indicating if this specific point initiated the drag
    let mut is_active = use_signal(|| false);

    // Retrieve the global drag context
    let ctx = use_context::<DragContext>();

    // Logic to update position:
    // We access the signals in the render phase. Dioxus subscribes to any signal
    // accessed inside rsx!. If `ctx.mouse_x` changes, this component re-renders.
    // If dragging, we snap our local state to the global cursor.

