// A no-op waker for initial polling
fn noop_waker() -> Waker {
    unsafe fn noop_clone(_: *const ()) -> RawWaker {
        noop_raw_waker()
    }

    unsafe fn noop Wake(_: *const ()) {}

    unsafe fn noop_drop(_: *const ()) {}

    unsafe fn noop_raw_waker() -> RawWaker {
        let vtable = &RawWakerVTable::new(noop_clone, noop_wake, noop_wake, noop_drop);
        RawWaker::new(core::ptr::null(), vtable)
    }

    unsafe { Waker::from_raw(noop_raw_waker()) }
}

// Helper function to manually poll a future once
fn try_poll_once<T>(future: &mut core::pin::Pin<&mut dyn core::future::Future<Output = T>>) -> Result<T, ()> {
    let mut cx = Context::from_waker(&noop_waker());
    match Pin::new(future).poll(&mut cx) {
        Poll::Ready(value) => Ok(value),
        Poll::Pending => Err(()),
    }
}

#[tokio::main]
