    println!("=== Tokio Manual Polling Demo ===\n");

    // Test 1: Future that completes immediately
    println!("Test 1: Immediate completion");
    test_immediate_future().await;
    println!();

    // Test 2: Future that needs time to complete
    println!("Test 2: Delayed completion");
    test_delayed_future().await;
    println!();

    // Test 3: Using senders/receivers
    println!("Test 3: Channel-based future");
    test_channel_future().await;
}

async fn test_immediate_future() {
    // Create a channel that already has data
    let (tx, rx) = oneshot::channel::<i32>();
    drop(tx.send(42)); // Send immediately

    // Convert to a mutable future pin
    let mut rx_pinned = Box::pin(rx);

    // Try to poll once synchronously
    match try_poll_once(&mut rx_pinned.as_mut_dyn()) {
        Ok(value) => println!("✓ Got value immediately: {}", value),
        Err(_) => {
            println!("✗ Would need to spawn task (unexpected for immediate)");
        }
    }
}

async fn test_delayed_future() {
    // Create a sleep future
    let mut sleep_fut = Box::pin(sleep(Duration::from_millis(10)));

    // Try to poll once
    match try_poll_once(&mut sleep_fut.as_mut_dyn()) {
        Ok(()) => println!("✓ Completed immediately (surprising for sleep!)"),
        Err(_) => {
