  "main.rs": "// Self-contained demo showing the 'Dedicated Worker Thread' pattern.
// This solves the Mutex Contention Freeze. 
// Note: To fully solve blocking read freezes, PTY FDs must be O_NONBLOCK + polled,
// which is complex with expectrl. This demo focuses on the Safe Concurrency pattern.

use crossbeam_channel::{bounded, Receiver, Sender};
use expectrl::Session;
use log::{info, warn};
use std::sync::{Arc, mpsc};
use std::thread;
use std::time::Duration;

/// Represents a PTY Agent running in a dedicated worker thread.
/// Ownership of the `Session` is transferred to the worker, eliminating
/// the need for Arc<Mutex<Session>> across UI and Read threads.
struct Agent {
    // Send commands to the Agent worker thread
    tx: Sender<AgentCommand>,
}

#[derive(Debug)]
enum AgentCommand {
    /// Forward a string (keystrokes) from the frontend to the PTY
    Send(String),
    /// Request shutdown
    Stop,
}

impl Agent {
    /// Creates a new agent and spawns the worker thread.
    fn spawn(agent_command: &str) -> Self {
        info!("Starting agent with command: {}", agent_command);
        let (tx, rx) = bounded::<AgentCommand>(100); // Buffer size matters for backpressure

        // The `manager_thread` owns the Session exclusively.
        // No locks are needed inside here; we just consume the channel.
        thread::Builder::new()
            .name("pty-manager".to_string())
            .spawn(move || {
                match Self::run_worker(rx, agent_command) {
                    Ok(_) => info!("Worker exited normally"),
                    Err(e) => warn!("Worker error: {}", e),
                }
            })
            .expect("Failed to spawn worker");

        Self { tx }
    }

    /// Internal worker loop managing the PTY Lifecycle.
    fn run_worker(rx: Receiver<AgentCommand>, cmd: &str) -> Result<(), Box<dyn std::error::Error>> {
        // 1. Start the PTY Session. The `expectrl::Session` holds the FD.
        let mut session = Session::spawn(None, &[cmd], "TERM=xterm-256color")?;

        // Note on Concurrency:
        // `session` is NOT wrapped in Mutex here. This thread has exclusive ownership.
        // The UI/Main thread sends data via `rx`, this thread pushes to `session`.

        loop {
            // 2. PRIORITY INPUT: Before trying to read from PTY, check for input from UI.
            // If the PTY is blocking on `read()`, this code would never execute!
            // In a production env with blocking `read()`, you'd need Non-blocking FDs.
            // Here we use a non-blocking poll strategy or try-recv.

            // Drain all incoming commands immediately to prevent buffer starvation
            while let Ok(command) = rx.recv_timeout(Duration::from_millis(1)) {
                match command {
                    AgentCommand::Send(data) => {
                        info!("Forwarding input: {:?}", data);
                        session.send(data.as_str()).expect("Send failed");
                    }
                    AgentCommand::Stop => {
                        info!("Stopping...");
                        return Ok(());
                    }
                }
            }

            // 3. READ LOOP
            // Since `session.read()` is blocking by default, the worker thread could hang here
            // waiting for output. During this hang, the `recv_timeout` above wouldn't run.
            // 
            // TO FIX COMPLETELY: You would need to set the Session's file descriptor
            // to O_NONBLOCK and use epoll/select/kqueue.
            // Since expectrl wraps this tightly, the architectural pattern fix below
            // relies on the fact that we removed the Global Mutex contention.
            // The app won't hang due to Lock Waits, but the Read itself still blocks the Thread.
            // (See comments in Cargo.toml about expectrl limitations).

            let mut buf = [0u8; 1024];
            // We catch errors to prevent the whole app dying on EOF if handled gracefully
            match session.read(&mut buf) {
                Ok(n) if n > 0 => {
                    let output = String::from_utf8_lossy(&buf[..n]).to_string();
                    // In Tauri, you would `app.emit("agent-output", output)` here.
                    // For this demo, we just print it.
                    print!("\rAgent Output: {}", output.trim()); 
                    io_flush();
                }
                Ok(0) => {
                    info!("Session closed (EOF)");
                    break;
                }
                Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                    // This branch only executes if FD is non-blocking.
                    // Default expectrl session is blocking, so this is unlikely unless modified.
                    continue;
                }
                Err(e) => {
                    warn!("Read error: {}", e);
                    continue;
                }
            }
        }

        Ok(())
    }

    /// Public interface to send input to the PTY (simulating Tauri Command).
    pub fn send(&self, data: &str) {
        let _ = self.tx.send(AgentCommand::Send(data.to_string()));
    }

    /// Shutdown the agent.
    pub fn stop(&self) {
        let _ = self.tx.send(AgentCommand::Stop);
    }
}

fn main() {
    env_logger::init();

    info!("Initializing Agent Demo...");

    // Spawn an 'ls' loop or a bash shell that keeps open
    let agent = Agent::spawn("bash");

    // Simulate Tauri UI interactions
    println!("Waiting 2 seconds to let shell init...");
    thread::sleep(Duration::from_secs(2));

