    agent.send("echo Hello World");
    thread::sleep(Duration::from_secs(1));

    println!("Sending 'pwd' to agent...");
    agent.send("pwd");
    thread::sleep(Duration::from_secs(1));

    // Simulate a situation where agent waits for input (blocking)
    // E.g., sending 'cat -' or just waiting. 
    // In the old Mutex pattern, if we called agent.send HERE, it would dead-lock if read held the lock.
    // In this Channel pattern, `tx.send` queues the message. 
    // The worker thread picks it up as soon as the blocking `read` yields.
    println!("\nSimulating input while Agent waits for output...");
    agent.send("date");
    agent.send("exit");

    // Give some time for final output
    thread::sleep(Duration::from_secs(3));

    agent.stop();
    info!("Demo finished.");
